window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q05"]=window.__LIBQ["pham-nhan-tu-tien"]["q05"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q05"]["factions"]={"updatedAt":"2026-07-14","count":60,"factions":[{"id":"lac-van-tong","name":"Lạc Vân Tông","cn":"落云宗","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Vân Mộng Sơn, Khê Quốc","nhanVatChinh":[],"blurb":"Lạc Vân Tông là một trong ba tông phái đứng đầu Khê Quốc, nổi tiếng về luyện đan thuật, cùng Cổ Kiếm Viện và Bách Xảo Viện liên hợp chiếm cứ Vân Mộng Sơn — nơi có Linh Nhãn Chi Thụ. Tông phái này đang trong kỳ thu nhận đệ tử, và Hàn Lập đã giả thân phận Luyện Khí kỳ để trà trộn vào.","detail":"Lạc Vân Tông là đại phái tu tiên lâu đời tại Khê Quốc, đặc biệt nổi danh về luyện đan thuật. Cùng Cổ Kiếm Viện và Bách Xảo Viện, ba tông phái này liên hợp chiếm cứ Vân Mộng Sơn — nơi sở hữu Linh Nhãn Chi Thụ, một nguồn tài nguyên tu luyện trọng yếu. Trong thời điểm tông phái mở kỳ thu nhận đệ tử, Hàn Lập đã giả mạo thân phận Luyện Khí kỳ để trà trộn vào nội bộ Lạc Vân Tông với mục đích riêng (@c0594).","nguonGoc":"Tông phái lâu đời tại Khê Quốc","tonChi":"Luyện đan thuật","quanHe":"Liên hợp với Cổ Kiếm Viện và Bách Xảo Viện chiếm cứ Vân Mộng Sơn","trangThai":"hưng","tabs":{"tienTrinh":[{"chuong":"@c0594","loai":"nhắc tới","importance":"major","giaiDoan":"Xuất hiện, Hàn Lập trà trộn","text":"Lạc Vân Tông đang thu nhận đệ tử, Hàn Lập giả thân phận Luyện Khí kỳ trà trộn vào với mục đích tiếp cận tông phái nổi tiếng luyện đan thuật.","trangThaiMoc":"hưng","anchor":"tu tiên đại phái “Lạc Vân Tông” nơi đây thu nhận đệ tử"}]},"nguon":["@c0594"]},{"id":"co-kiem-vien","name":"Cổ Kiếm Viện","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Vân Mộng Sơn, Khê Quốc","nhanVatChinh":[],"blurb":"Một trong ba tông phái đứng đầu Khê Quốc, liên hợp chiếm cứ Vân Mộng Sơn.","detail":"Tông phái tu tiên tại Khê Quốc, cùng Lạc Vân Tông và Bách Xảo Viện liên hợp chiếm cứ Vân Mộng Sơn.","quanHe":"Liên hợp với Lạc Vân Tông và Bách Xảo Viện chiếm cứ Vân Mộng Sơn","trangThai":"hưng","tabs":{"tienTrinh":[{"chuong":"@c0594","loai":"nhắc tới","importance":"normal","giaiDoan":"Xuất hiện","text":"Được giới thiệu là một trong ba tông phái chiếm cứ Vân Mộng Sơn.","anchor":"do “Cổ Kiếm Viện” “Lạc Vân Tông” “Bách Xảo Viện” ba cái tông phái liên hợp chiếm cứ"}]},"nguon":["@c0594"]},{"id":"bach-xao-vien","name":"Bách Xảo Viện","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Vân Mộng Sơn, Khê Quốc","nhanVatChinh":["Phó lão giả","Thạch lão giả","Xương Chánh trưởng lão","Đại hán đầu hói"],"blurb":"Bách Xảo Viện là một trong ba tông phái đứng đầu Khê Quốc, cùng Cổ Kiếm Môn và Lạc Vân Tông liên hợp chiếm cứ Vân Mộng Sơn. Tông phái này từng đăng cai tổ chức Thí Kiếm Đại Hội ba phái tại Vân Mông Tây Mạch.","detail":"Bách Xảo Viện là tông phái tu tiên tọa lạc tại Vân Mông Tây Mạch thuộc Vân Mộng Sơn, Khê Quốc. Cùng với Cổ Kiếm Môn và Lạc Vân Tông, Bách Xảo Viện là một trong ba đại phái liên hợp chiếm cứ Vân Mộng Sơn. Ba phái định kỳ tổ chức Thí Kiếm Đại Hội để thi đấu tranh đoạt; trong đó Bách Xảo Viện và Lạc Vân Tông được ghi nhận là chưa từng đoạt quán quân tại đại hội này (@c0615). Bách Xảo Viện từng đứng ra đăng cai Thí Kiếm Đại Hội, nghênh đón hai phái còn lại đến tham dự tại trụ sở ở Vân Mông Tây Mạch (@c0624).","quanHe":"Liên hợp với Cổ Kiếm Viện và Lạc Vân Tông chiếm cứ Vân Mộng Sơn","trangThai":"hoat-dong","tabs":{"tienTrinh":[{"chuong":"@c0594","loai":"nhắc tới","importance":"normal","giaiDoan":"Xuất hiện","text":"Được giới thiệu là một trong ba tông phái chiếm cứ Vân Mộng Sơn.","anchor":"do “Cổ Kiếm Viện” “Lạc Vân Tông” “Bách Xảo Viện” ba cái tông phái liên hợp chiếm cứ"},{"chuong":"@c0615","loai":"nhắc tới","importance":"normal","giaiDoan":"Tiết lộ thông tin cơ bản","trangThaiMoc":"hoat-dong","text":"Được nhắc đến là một trong ba phái Vân Mộng Sơn tham gia Thí Kiếm Đại Hội, cùng Lạc Vân Tông chưa từng đoạt quán quân.","anchor":"Đệ tử chúng ta cùng Bách Xảo Viện chỉ có thể đứng ngoài"},{"chuong":"@c0618","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nhắc tới trong thông báo Thí Kiếm đại hội","text":"Cổ Kiếm Môn gửi thông hàm, Thí Kiếm đại hội nửa năm sau tổ chức tại Bách Xảo Viện ở Vân Mông Tây Mạch, ba phái mỗi bên 30 đệ tử.","anchor":"lần này, địa điểm tổ chức sẽ là Bách Xảo Viện"},{"chuong":"@c0624","loai":"xuat-hien","importance":"major","giaiDoan":"Đăng cai Thí Kiếm Đại Hội","trangThaiMoc":"đăng cai","text":"Bách Xảo Viện đăng cai Thí Kiếm Đại Hội ba phái, nghênh đón Cổ Kiếm Môn và Lạc Vân Tông.","anchor":"Bách Xảo Viện đón tiếp hai phái xong thì dẫn Cổ Kiếm Môn và Lạc Vân Tông nghỉ tại hai trạch viện lớn một ngày"}]},"nguon":["@c0594","@c0615","@c0618","@c0624"],"cn":"百巧院","thanhVien":[{"ten":"Phó lão giả","chucVu":"Viện chủ","tuChuong":"@c0624","trangThai":"dang-hoat-dong"},{"ten":"Thạch lão giả","chucVu":"Kết Đan tu sĩ","tuChuong":"@c0624","trangThai":"dang-hoat-dong"},{"ten":"Xương Chánh trưởng lão","chucVu":"Trưởng lão","tuChuong":"@c0624","trangThai":"xuat-ngoai"},{"ten":"Đại hán đầu hói","chucVu":"Trọng tài Thí Kiếm Đại Hội","tuChuong":"@c0624","trangThai":"dang-hoat-dong"}],"dacDiem":"Trụ sở đặt tại Vân Mông Tây Mạch thuộc Vân Mộng Sơn; cùng Lạc Vân Tông chưa từng đoạt quán quân Thí Kiếm Đại Hội (@c0615).","congNang":["Tham gia Thí Kiếm Đại Hội ba phái Vân Mộng Sơn (@c0615)","Đăng cai tổ chức Thí Kiếm Đại Hội tại trụ sở Vân Mông Tây Mạch, nghênh đón Cổ Kiếm Môn và Lạc Vân Tông (@c0624)"]},{"id":"thien-dao-minh","name":"Thiên Đạo Minh","cn":"天道盟","type":"lien-minh","typeLabel":"Liên minh","diaBan":"Khê quốc và hai quốc gia lân cận","nhanVatChinh":["Đồng tử họ Lam"],"blurb":"Thiên Đạo Minh là liên minh lỏng lẻo do tu sĩ hơn mười quốc gia tại Thiên Nam thành lập sau khi Hàn Lập rời đi, nhằm đối trọng với hai thế lực chính đạo và ma đạo. Cổ Kiếm Môn, Lạc Vân Tông và Bách Xảo Môn là nòng cốt của liên minh này.","detail":"Thiên Đạo Minh được thành lập sau khi Hàn Lập rời khỏi Thiên Nam, là liên minh lỏng lẻo quy tụ tu sĩ từ hơn mười quốc gia nhằm tạo thế đối chọi với chính đạo và ma đạo. Khê quốc cùng hai quốc gia lân cận nằm trong phạm vi ảnh hưởng của Thiên Đạo Minh. Ba tông môn giữ vai trò trung tâm là Cổ Kiếm Môn, Lạc Vân Tông và Bách Xảo Môn. Cùng với chính đạo và ma đạo, Thiên Đạo Minh duy trì trạng thái cân bằng xảo diệu — không bên nào dám gây sự lớn, hình thành thế chân vạc tại vùng tu tiên Thiên Nam. @c0595","nguonGoc":"Thành lập sau khi Hàn Lập rời Thiên Nam, do tu sĩ hơn mười quốc gia liên minh","quyMo":"Hơn mười quốc gia","quanHe":"Đối trọng chính đạo và ma đạo; thành viên hiệp nghị bốn thế lực chống Mạc Lan","trangThai":"Đang hoạt động","capNhatToi":"@c0595","thanhVien":[{"ten":"Cổ Kiếm Môn","chucVu":"trung tâm thế lực","tuChuong":"@c0595","trangThai":"dang-hoat-dong"},{"ten":"Lạc Vân Tông","chucVu":"trung tâm thế lực","tuChuong":"@c0595","trangThai":"dang-hoat-dong"},{"ten":"Bách Xảo","chucVu":"trung tâm thế lực","tuChuong":"@c0595","trangThai":"dang-hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0595","loai":"lap","importance":"major","giaiDoan":"Thành lập và cân bằng thế lực","text":"Liên minh lỏng lẻo hơn mười quốc gia thành lập để đối chọi chính đạo và ma đạo. Cổ Kiếm Môn, Lạc Vân Tông, Bách Xảo là trung tâm. Cùng ba thế lực còn lại đạt cân bằng xảo diệu tại Thiên Nam.","anchor":"do tu sĩ của mười mấy quốc gia liên minh lại thành lập lực lượng để đối chọi với hai tổ chức ma giáo và chính giáo"}]},"nguon":["@c0595","@c0631","@c0671"],"dacDiem":"Liên minh mang tính lỏng lẻo, không phải một tông phái thống nhất mà là sự liên kết của tu sĩ nhiều quốc gia, lấy ba tông môn Cổ Kiếm Môn, Lạc Vân Tông, Bách Xảo Môn làm nòng cốt. @c0595"},{"id":"mac-lan-bo-lac","name":"Mạc Lan bộ lạc","cn":"莫兰部落","type":"bo-lac","typeLabel":"Bộ lạc","diaBan":"Biên giới Thiên Nam","nhanVatChinh":[],"blurb":"Mạc Lan bộ lạc là một bộ lạc pháp sĩ hoạt động tại biên giới Thiên Nam, đối đầu trực tiếp với Cửu Quốc Minh. Sau khi nhận tiếp viện từ Mạc Lan đệ nhị và Mạc Lan đệ tứ, lực lượng pháp sĩ tăng gấp bội, từng áp đảo và cướp lãnh thổ của đối phương trước khi bị chặn lại trong một đại chiến quyết định.","detail":"Mạc Lan bộ lạc giằng co lâu dài với Cửu Quốc Minh tại biên giới Thiên Nam. Tới một thời điểm, bộ lạc nhận được tiếp viện từ Mạc Lan đệ nhị và Mạc Lan đệ tứ, khiến số lượng pháp sĩ tăng gấp bội. Nhờ ưu thế quân số, Mạc Lan bộ lạc áp đảo Cửu Quốc Minh, cướp được một số vùng lãnh thổ. Tuy nhiên, đà tiến công bị chặn đứng trong một đại chiến quyết định có hơn ngàn tu sĩ tử trận.","quyMo":"Pháp sĩ tăng gấp bội sau tiếp viện","trangThai":"bị chặn, đang giằng co","capNhatToi":"@c0595","tabs":{"tienTrinh":[{"chuong":"@c0595","loai":"khai-chien","importance":"major","giaiDoan":"Tiếp viện và đại chiến với Cửu Quốc Minh","trangThaiMoc":"tăng cường → bị chặn","text":"Nhận tiếp viện từ Mạc Lan đệ nhị và đệ tứ, pháp sĩ tăng gấp bội. Áp đảo Cửu Quốc Minh, cướp lãnh thổ. Bị chặn lại sau đại chiến quyết định.","anchor":"Mạc Lan bộ lạc giằng co đã lâu với Cửu Quốc Minh bỗng nhiên nhận được tiếp viện đến từ các tộc Mạc Lan đệ nhị và Mạc Lan đệ tứ"}]},"nguon":["@c0595"],"uyLuc":"Sau khi nhận tiếp viện, lực lượng pháp sĩ tăng gấp bội, đủ sức áp đảo Cửu Quốc Minh và cướp lãnh thổ; đại chiến quyết định có hơn ngàn tu sĩ tử trận (@c0595).","dacDiem":"Bộ lạc pháp sĩ có cấu trúc phân nhánh (ít nhất gồm Mạc Lan đệ nhị và Mạc Lan đệ tứ), có khả năng huy động tiếp viện liên bộ lạc để tập trung lực lượng cho chiến tranh biên giới."},{"id":"co-kiem-mon","name":"Cổ Kiếm Môn","cn":"古剑门","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Vân Mộng Sơn (vị trí chính), Khê Quốc","nhanVatChinh":["Khương Vân","Thanh bào nho sinh","Bạch y thiếu phụ","Diêu Phong"],"blurb":"Cổ Kiếm Môn là một trong ba phái lớn chiếm cứ Vân Mộng Sơn thuộc Khê Quốc, nổi danh là môn phái kiếm tu với thực lực cường đại nhất trong ba phái. Tông môn sở hữu tuyệt học trấn phái Thái Bạch Kiếm Quyết, chuyên về ngự kiếm thuật và kiếm khí phi hành, song yêu cầu linh căn cực cao nên số lượng đệ tử ít nhất trong ba phái.","detail":"Cổ Kiếm Môn tọa lạc tại Vân Mộng Sơn, Khê Quốc, là tông môn chuyên về kiếm tu, am hiểu ngự kiếm thuật. Trong ba phái cùng chia sẻ vị trí tại Vân Mộng Sơn, Cổ Kiếm Môn được đánh giá có thực lực cường đại nhất, nhờ sở hữu tuyệt học trấn phái Thái Bạch Kiếm Quyết — một công pháp mang tính công kích siêu cường, đệ tử tu vi đại thành thì cùng cấp ít ai sánh được. Tuy nhiên, công pháp này yêu cầu linh căn cực cao, khiến môn phái tuy mạnh nhưng số đệ tử lại ít nhất trong ba phái. Cổ Kiếm Môn có thu nạp cả tán tu, song số lượng vẫn hạn chế. Đệ tử môn phái sử dụng kiếm khí phi hành làm phương thức di chuyển. Trong Thí Kiếm Đại Hội tại Bách Xảo Viện, đệ tử Cổ Kiếm Môn là Diêu Phong đã tham chiến nhưng thua trận đầu trước Hàn Lập (@c0624).","nguonGoc":"Không rõ","tonChi":"Chuyên ngự kiếm thuật","quyMo":"Ít đệ tử nhất trong ba phái do yêu cầu linh căn cao","tabs":{"tienTrinh":[{"chuong":"@c0596","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập cân nhắc gia nhập","text":"Hàn Lập phân tích Cổ Kiếm Môn: thực lực mạnh nhất ba phái, có Thái Bạch Kiếm Quyết nhưng yêu cầu linh căn quá cao nên bỏ qua.","anchor":"đệ tử Cổ Kiếm Môn một khi tu vi đại thành, bằng vào tính công kích siêu cường, các tu sĩ cùng cấp thường không phải là đối thủ"},{"chuong":"@c0615","loai":"nhắc tới","importance":"major","giaiDoan":"Tiết lộ thông tin cơ bản","trangThaiMoc":"hoat-dong","text":"Được Vương sư huynh giới thiệu là một trong ba phái Vân Mộng Sơn, môn phái kiếm tu với công pháp và kiếm khí lợi hại phi thường, luôn đoạt quán quân Thí Kiếm Đại Hội để chiếm phần lớn thuần dịch Linh Nhãn Chi Thụ.","anchor":"môn phái kiếm tu Cổ Kiếm Môn người ta, vô luận là công pháp hay kiếm khí đều lợi hại phi thường"},{"chuong":"@c0624","loai":"xuat-hien","importance":"major","giaiDoan":"Tham gia Thí Kiếm Đại Hội","trangThaiMoc":"tham dự","text":"Cổ Kiếm Môn đến Bách Xảo Viện bằng kiếm khí phi hành dự Thí Kiếm Đại Hội. Diêu Phong thua trận đầu trước Hàn Lập.","anchor":"Là Cổ Kiếm Môn, bọn họ chính là sử dụng kiếm khí phi hành"}]},"nguon":["@c0596","@c0615","@c0624"],"trangThai":"hoat-dong","thanhVien":[{"ten":"Khương Vân","chucVu":"Trưởng đoàn (Kết Đan)","tuChuong":"@c0624","trangThai":"dang-hoat-dong"},{"ten":"Thanh bào nho sinh","chucVu":"Kết Đan tu sĩ, Bạch Bích Song Kiếm","tuChuong":"@c0624","trangThai":"dang-hoat-dong"},{"ten":"Bạch y thiếu phụ","chucVu":"Kết Đan tu sĩ, Bạch Bích Song Kiếm","tuChuong":"@c0624","trangThai":"dang-hoat-dong"},{"ten":"Diêu Phong","chucVu":"Đệ tử Trúc Cơ sơ kỳ","tuChuong":"@c0624","trangThai":"thua-tran"}],"uyLuc":"Thực lực cường đại nhất trong ba phái Vân Mộng Sơn, đệ tử luyện thành Thái Bạch Kiếm Quyết thì cùng cấp ít ai địch nổi (@c0596).","dacDiem":"Môn phái kiếm tu thuần chất, công pháp yêu cầu linh căn cực cao nên tuy thực lực mạnh nhất nhưng số đệ tử lại ít nhất trong ba phái tại Vân Mộng Sơn.","congNang":["Ngự kiếm thuật — kỹ thuật điều khiển kiếm chiến đấu, là sở trường cốt lõi của môn phái (@c0615)","Kiếm khí phi hành — sử dụng kiếm khí làm phương thức di chuyển trên không (@c0624)","Thái Bạch Kiếm Quyết — tuyệt học trấn phái, tính công kích siêu cường, đệ tử tu vi đại thành thì cùng cấp ít đối thủ; yêu cầu linh căn cực cao (@c0596)"]},{"id":"an-kiem-phong","name":"Ẩn Kiếm Phong","cn":"隐剑峰","type":"phan-nhanh","typeLabel":"Phân nhánh thế lực","diaBan":"Lạc Vân Tông","nhanVatChinh":["Lão giả tóc xám trắng"],"blurb":"Một trong lục Phong của Lạc Vân Tông, chủ tu công pháp kim thuộc tính. Lần thu đệ tử trước chỉ nhận hai người nhưng đều có hai linh căn.","detail":"Ẩn Kiếm Phong chuyên về công pháp kim thuộc tính trong Lạc Vân Tông. Đại diện là lão giả tóc xám trắng, đã tranh đệ tử có Đoán kim chi thể nhưng không thành, chưởng môn phân đệ tử đó về Huyễn Thạch Phong.","nguonGoc":"Thuộc Lạc Vân Tông","tonChi":"Chủ tu công pháp kim thuộc tính","tabs":{"tienTrinh":[{"chuong":"@c0599","loai":"nhắc tới","importance":"normal","giaiDoan":"Tranh đệ tử Đoán kim chi thể","text":"Đại diện Ẩn Kiếm Phong tranh đệ tử có Đoán kim chi thể, viện lý phong chủ tu kim thuộc tính, nhưng chưởng môn quyết định phân đệ tử đó về Huyễn Thạch Phong.","anchor":"ta chỉ muốn có được tên đệ tử có Đoán kim chi thể để Ẩn Kiếm Phong chúng ta dạy dỗ"}]},"nguon":["@c0599"]},{"id":"hoa-van-phong","name":"Hỏa Vân Phong","cn":"火云峰","type":"phan-nhanh","typeLabel":"Phân nhánh thế lực","diaBan":"Lạc Vân Tông","nhanVatChinh":["Trung niên sắc mặt trắng","Lý sư bá"],"blurb":"Một trong lục Phong của Lạc Vân Tông, lấy hỏa thuộc tính công pháp làm chính, nhưng cũng có Lý sư bá tu Kim Luyện quyết nổi danh.","detail":"Hỏa Vân Phong chuyên hỏa thuộc tính công pháp, tuy nhiên cũng có Lý sư bá tu Kim Luyện quyết nổi danh ở Khê Quốc. Đại diện trung niên sắc mặt trắng tranh đệ tử Đoán kim chi thể nhưng không thành.","nguonGoc":"Thuộc Lạc Vân Tông","tonChi":"Hỏa thuộc tính công pháp là chính","thanhVien":[{"ten":"Lý sư bá","chucVu":"Sư bá","tuChuong":"@c0599","trangThai":"dang-hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0599","loai":"nhắc tới","importance":"normal","giaiDoan":"Tranh đệ tử Đoán kim chi thể","text":"Đại diện Hỏa Vân Phong viện dẫn Lý sư bá với Kim Luyện quyết nổi danh ở Khê Quốc để tranh đệ tử Đoán kim chi thể, nhưng chưởng môn phân về Huyễn Thạch Phong.","anchor":"Hỏa Vân Phong chúng ta cũng có Lý sư bá với Kim Luyện quyết ở Khê Quốc này cũng rất là nổi danh"}]},"nguon":["@c0599"]},{"id":"huyen-thach-phong","name":"Huyễn Thạch Phong","cn":"幻石峰","type":"phan-nhanh","typeLabel":"Phân nhánh thế lực","diaBan":"Lạc Vân Tông","nhanVatChinh":[],"blurb":"Một trong lục Phong của Lạc Vân Tông. Thanh niên có Đoán kim chi thể được chưởng môn phân về đây.","detail":"Huyễn Thạch Phong là một trong lục Phong của Lạc Vân Tông, được chưởng môn Ngụy Nhất Minh chọn làm nơi tiếp nhận đệ tử có Đoán kim chi thể khi Ẩn Kiếm Phong và Hỏa Vân Phong tranh chấp không phân thắng bại.","nguon":["@c0599"]},{"id":"thien-tuyen-phong","name":"Thiên Tuyền Phong","cn":"天泉峰","type":"chi-phong","typeLabel":"Chi phong","diaBan":"Tuyền Phong Sơn","nhanVatChinh":["Sư tổ (trung niên nho sinh, Kết Đan trung kỳ)","Du Quân","Tam sư huynh (bạch phát lão giả)","Mộ Phái Linh","Mã sư muội","Tân sư đệ"],"blurb":"Một ngọn phong do vị trung niên nho sinh tu vi Kết Đan trung kỳ làm chủ, có các đệ tử tinh thông chế phù thuật và luyện đan dược, đồng thời thu nhận ngoại môn đệ tử mới.","detail":"Thiên Tuyền Phong tọa lạc trên Tuyền Phong Sơn, có dãy lầu các và sương phòng u tĩnh nơi sư tổ cư ngụ. Sư tổ là tu sĩ Kết Đan trung kỳ, tướng mạo cổ quái, ba chòm râu đen, trang phục nho sinh. Dưới quyền có Du Quân, tam sư huynh (bạch phát lão giả gần sáu mươi, tinh thông chế phù thuật) và Mộ Phái Linh (ngũ sư tỷ, Trúc Cơ trung kỳ, am hiểu luyện đan dược). Ngoài ra còn Mã sư muội và Tân sư đệ — hậu bối tục giới của sư tổ, chưa chính thức được thu nhận nhưng chỉ là sớm muộn, có bối phận đặc biệt cao. Thiên Tuyền Phong nhận ngoại môn đệ tử mới gồm Hàn Lập (phân cho Mộ Phái Linh, trông coi dược viên) và Đỗ Đông (phân cho tam sư huynh, phụ giúp chế phù). Phía sau động phủ Mộ Phái Linh có dược viên rộng hơn trăm trượng với vài loại dược thảo, ba tòa nhà tranh và một ngọn núi nhỏ.","nguon":["@c0600"]},{"id":"ngan-nguyet-lang-toc","name":"Ngân Nguyệt lang tộc","cn":"银月狼族","type":"yeu-toc","typeLabel":"Yêu tộc","diaBan":"Không rõ","nhanVatChinh":["Ngân Nguyệt"],"blurb":"Tộc yêu thú mà Ngân Nguyệt tự nhận là thành viên dựa trên ký ức kiếp trước tàn khuyết. Sở hữu thiên phú thôn phệ linh hồn.","detail":"Ngân Nguyệt tự xưng là thành viên Ngân Nguyệt lang tộc, tên do cô tự đặt dựa trên ký ức tàn khuyết. Hàn Lập cho biết chưa từng thấy loài yêu thú này trong điển tịch, Ngân Nguyệt cũng thừa nhận có thể nhớ lầm. Tộc này sở hữu thiên phú thôn phệ linh hồn và thiên sinh khắc chế Tứ đồng linh hồ.","nguonGoc":"Không rõ, có thể là giống loài cổ xưa hoặc đã tuyệt chủng","dacDiem":"Thiên phú thôn phệ linh hồn, thiên sinh khắc chế Tứ đồng linh hồ","thanhVien":[{"ten":"Ngân Nguyệt","chucVu":"Thành viên (ký ức tàn khuyết)","tuChuong":"@c0612","trangThai":"dang-hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0612","loai":"nhắc tới","importance":"normal","giaiDoan":"Ngân Nguyệt tự thuật","trangThaiMoc":"Không rõ tình trạng hiện tại","text":"Ngân Nguyệt tự xưng là thành viên Ngân Nguyệt lang tộc dựa trên ký ức tàn khuyết kiếp trước. Hàn Lập cho biết chưa thấy trong điển tịch.","anchor":"Ta chưa thấy trong điển tịch có nói đến loài yêu thú này"}]},"nguon":["@c0612"]},{"id":"van-mong-son-tam-phai","name":"Tam phái Vân Mộng Sơn","cn":"","type":"lien-minh","typeLabel":"Liên minh tông phái","diaBan":"Vân Mộng Sơn","nhanVatChinh":[],"blurb":"Liên minh ba tông phái trên Vân Mộng Sơn, tổ chức Thí Kiếm Đại Hội và điều chế Minh Thanh Linh Thuỷ.","detail":"Liên minh của ba tông phái trên Vân Mộng Sơn (gồm Lạc Vân Tông, Cổ Kiếm Môn và một phái nữa). Định kỳ tổ chức Thí Kiếm Đại Hội cho đệ tử tỷ thí, phần thưởng gồm Định Linh Đan (quán quân) và Minh Thanh Linh Thuỷ (top mười). Tiền bối Kết Đan kỳ trong ba phái thường cấp pháp khí uy lực lớn cho con cháu đệ tử tham dự đại hội.","tabs":{"tienTrinh":[{"chuong":"@c0616","loai":"nhắc tới","importance":"normal","giaiDoan":"Tổ chức Thí Kiếm Đại Hội, triệu tập đệ tử","text":"Tam phái Vân Mộng Sơn điều chế Minh Thanh Linh Thuỷ làm phần thưởng top mười Thí Kiếm Đại Hội, tiền bối Kết Đan kỳ cấp pháp khí cho con cháu tham gia.","anchor":"tam phái Vân Mộng Sơn lại điều chế nó"}]},"capNhatToi":"@c0616","nguon":["@c0616"]},{"id":"bach-phuong-phong","name":"Bạch Phượng Phong","type":"tong-mon","typeLabel":"Phong (thuộc Hoàng Phong Cốc)","diaBan":"Vân Mộng Sơn","nhanVatChinh":["Kim Dung"],"blurb":"Một trong Lục Xảo Phong thuộc Hoàng Phong Cốc, hai vị Phong chủ đều là nữ tu sĩ Kết Đan kỳ, đệ tử lấy nữ làm chính, số lượng không đông.","detail":"Bạch Phượng Phong là thế lực đặc thù trong Lục Xảo Phong: cả hai Phong chủ đều là nữ tu sĩ Kết Đan kỳ, môn hạ đệ tử cũng chủ yếu là nữ. Trong tỷ thí Lục Xảo Phong chỉ có mười mấy nữ đệ tử trẻ tham gia, số lượng ít nhất trong các phong.","nguon":["@c0619"],"tabs":{"tienTrinh":[{"chuong":"@c0619","loai":"nhac-toi","importance":"normal","giaiDoan":"Tỷ thí Lục Xảo Phong","text":"Được giới thiệu là phong có hai Phong chủ nữ Kết Đan kỳ, đệ tử chủ yếu nữ, chỉ mười mấy người tham gia tỷ thí.","anchor":"Hai vị Phong chủ không những đều là nữ tu sĩ Kết đan kỳ mà môn hạ đệ tử cũng lấy nữ làm chính"}]}},{"id":"tuan-gia","name":"Tuân gia","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Khê quốc","nhanVatChinh":["Tuân Thông"],"blurb":"Tu tiên gia tộc đỉnh đỉnh đại danh ở Khê quốc, sở hữu pháp khí Hoả Lãng châu nổi danh.","detail":"Gia tộc tu tiên nổi danh ở Khê quốc, Tuân sư đệ (Tuân Thông) xuất thân từ đây, được các trưởng bối toàn tâm dạy dỗ từ nhỏ. Gia tộc sở hữu pháp khí gia truyền Hoả Lãng châu.","nguon":["@c0620"]},{"id":"do-gia","name":"Đỗ gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"","nhanVatChinh":["Đỗ Đông"],"blurb":"Gia tộc tu tiên bị tiêu diệt hai trăm năm trước, trấn tộc chi bảo là Hàn Nguyệt Luân. Đỗ Đông bị nghi là hậu nhân mai danh ẩn tích.","detail":"Gia tộc tu tiên đã bị tiêu diệt hai trăm năm trước. Trấn tộc chi bảo là Hàn Nguyệt Luân — đỉnh cấp pháp khí thuộc tính băng. Đỗ Đông hiện sở hữu Hàn Nguyệt Luân, bị các trưởng lão Lạc Vân Tông suy đoán là hậu nhân Đỗ gia mai danh ẩn tích, nay thấy an toàn mới xuất hiện.","trangThai":"da-diet","nguon":["@c0621","@c0623"]},{"id":"thuong-quan-gia-toc","name":"Thượng Quan gia tộc","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"","nhanVatChinh":[],"blurb":"Gia tộc tu tiên có đệ tử trực hệ gia nhập Bách Xảo Viện, khi còn Luyện Khí Kỳ đã dùng pháp khí tự luyện chế đánh bại trưởng bối.","detail":"Gia tộc tu tiên, có đệ tử trực hệ gia nhập Bách Xảo Viện. Đệ tử này khi còn Luyện Khí Kỳ đã có thể dùng pháp khí do bản thân luyện chế đánh bại tu sĩ bậc trưởng bối.","nguon":["@c0621"]},{"id":"hao-nhien-cac","name":"Hạo Nhiên Các","cn":"","type":"chinh-dao","typeLabel":"Chính đạo","diaBan":"","nhanVatChinh":["Nho sinh","Lão giả họ Mã"],"blurb":"Thế lực chính đạo, cài gián điệp (nho sinh họ Bạch) trà trộn Cổ Kiếm Môn hơn trăm năm, bị đồng tử Lam sư thúc lật tẩy.","detail":"Nho sinh họ Bạch là nhập môn đệ tử của Hạo Nhiên Các, trà trộn vào Cổ Kiếm Môn hơn trăm năm. Khi bị lộ, bạo phát nhắm bắt Mạnh Địch (Cửu Linh Kiếm Thể), cho thấy mục tiêu thực sự. Được đồng tử gọi là chính đạo Hạo Nhiên Các.","thanhVien":[{"ten":"Nho sinh","chucVu":"Nhập môn đệ tử (gián điệp)","tuChuong":"@c0627","trangThai":"bi-bat"},{"ten":"Lão giả họ Mã","chucVu":"Tu sĩ Nguyên Anh","tuChuong":"@c0725","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0627","loai":"nhắc tới","importance":"normal","giaiDoan":"Gián điệp bị lật tẩy","text":"Nho sinh họ Bạch bị đồng tử Lam sư thúc lật tẩy là nhập môn đệ tử Hạo Nhiên Các cài vào Cổ Kiếm Môn hơn trăm năm.","anchor":"thân là nhập môn đệ tử của chính đạo Hạo Nhiên Các các chủ"},{"chuong":"@c0725","loai":"nhắc tới","importance":"normal","giaiDoan":"Phái người chi viện","text":"Lão giả họ Mã thuộc Hạo Nhiên Các được phái đi cùng Hàn Lập trấn thủ biên giới Ngu Quốc.","anchor":"một lão giả họ Mã của Hạo Nhiên Các thuộc Chính Đạo Minh"}]},"nguon":["@c0627","@c0725"]},{"id":"thien-huyen-tong","name":"Thiên Huyễn Tông","cn":"天幻宗","type":"tong-mon","typeLabel":"Tông môn","diaBan":"","nhanVatChinh":["Bạch tu sĩ","Đỗ Đông"],"blurb":"Thiên Huyễn Tông là một tông môn thuộc Ma đạo, đã cài gian tế trà trộn vào Cổ Kiếm Môn trong phe Chánh đạo. Bạch tu sĩ tự xưng đệ tử đích truyền, còn Đỗ Đông chính là thiếu chủ của tông môn này, cả hai phối hợp tấn công Cổ Kiếm Môn từ bên trong.","detail":"Thiên Huyễn Tông là một tông môn thuộc phe Ma đạo. Tông môn đã thực hiện kế hoạch cài gian tế xâm nhập Cổ Kiếm Môn — một môn phái thuộc Chánh đạo minh. Bạch tu sĩ trà trộn vào Cổ Kiếm Môn dưới danh nghĩa \"Bạch sư thúc\", tự xưng là đệ tử đích truyền của Thiên Huyễn Tông; khi sự việc bại lộ, y phá cửa tĩnh thất hé lộ thân phận thật. Đỗ Đông là đồng bọn phối hợp từ trước, thực chất mang thân phận thiếu chủ Thiên Huyễn Tông. Đỗ Đông từng bảo chứng giúp Bạch tu sĩ thoát chết khi bị lão quái vật dùng kiếm ti chế trụ. Đỗ Đông còn nhắc đến sư thúc và Tần tiền bối cần phối hợp ra tay, cho thấy Thiên Huyễn Tông còn nhiều nhân vật chưa lộ diện tham gia vào kế hoạch này. Đỗ Đông đã thi triển Đại La Thiên Huyễn Quyết — pháp quyết trấn phái của tông môn.","nguonGoc":"","tonChi":"","lanhDaoHienThoi":"","capBac":"","quyMo":"","trangThai":"hoat-dong","thanhVien":[{"ten":"Bạch tu sĩ","chucVu":"đệ tử đích truyền","tuChuong":"@c0629","trangThai":"hoat-dong"},{"ten":"Đỗ Đông","chucVu":"Thiếu chủ","tuChuong":"@c0629","trangThai":"dang-hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0629","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện trong Chánh đạo minh","text":"Bạch tu sĩ phá cửa tĩnh thất tự xưng đệ tử đích truyền Thiên Huyễn Tông, hé lộ đã cài gian tế vào Cổ Kiếm Môn. Phối hợp với Đỗ Đông và quân tấn công bên ngoài tạo thế đánh trong đánh ngoài.","anchor":"Đệ tử đích truyền của Ma đạo Thiên Huyễn Tông"},{"chuong":"@c0630","loai":"nhắc tới","importance":"major","giaiDoan":"Lộ diện qua Đỗ Đông","text":"Đỗ Đông lộ thân phận thiếu chủ Thiên Huyễn Tông, thi triển Đại La Thiên Huyễn Quyết trấn phái pháp quyết. Lão giả tóc rối nhắc Đỗ Đông không màng nguy hiểm mà tiến vào Lạc Vân Tông tạo điều kiện chánh tà hợp tác.","anchor":"nếu nói về ẩn nặc công pháp thì Thiên Huyễn Tông tại Thiên Nam nói là đệ nhị thì không ai dám nói là đệ nhất"}]},"nguon":["@c0629","@c0630"],"dacDiem":"Tông môn Ma đạo có khả năng cài gian tế dài hạn vào nội bộ các môn phái Chánh đạo, bố trí nhân sự phối hợp tấn công từ bên trong.","congNang":["Đại La Thiên Huyễn Quyết — pháp quyết trấn phái của Thiên Huyễn Tông, do Đỗ Đông thi triển @c0630"]},{"id":"chanh-dao-minh","name":"Chánh đạo minh","cn":"正道盟","type":"lien-minh","typeLabel":"Liên minh","diaBan":"Không rõ","nhanVatChinh":["Trung niên nho sinh"],"blurb":"Liên minh chánh đạo, đã cài gián điệp (nho sinh họ Bạch) trong phe ma đạo. Có mối liên hệ bí mật thân cận với Ma đạo lục tông.","detail":"Nho sinh họ Bạch là gián điệp Chánh đạo minh cài trong phe ma đạo, tuân lệnh Đỗ Đông (thiếu chủ Thiên Huyễn Tông). Nho sinh ngạc nhiên về việc Chánh đạo minh và Ma đạo lục tông thân cận. Gián điệp bại lộ trong bẫy phản gián của ba phái.","thanhVien":[{"ten":"Trung niên nho sinh","chucVu":"Gián điệp cài trong ma đạo","tuChuong":"@c0631","trangThai":"bại lộ"}],"tabs":{"tienTrinh":[{"chuong":"@c0631","loai":"nhắc tới","importance":"normal","giaiDoan":"Gián điệp bại lộ","text":"Nho sinh họ Bạch bại lộ thân phận gián điệp Chánh đạo minh trong bẫy phản gián của ba phái. Lộ mối liên hệ bí mật giữa Chánh đạo minh và Ma đạo lục tông.","anchor":"không biết từ lúc nào mà Chánh đạo minh cùng Ma đạo lục tông thân cận như thế"}]},"nguon":["@c0631"]},{"id":"thien-dao-tong","name":"Thiên Đạo Tông","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Không rõ","nhanVatChinh":[],"blurb":"Tông phái chánh đạo được ba phái (Lạc Vân Tông, Cổ Kiếm Môn, Hạo Nhiên Các) nhờ làm trung gian gây áp lực lên chánh ma lưỡng đạo sau vụ mai phục, nhưng bất thành.","detail":"Ba phái thông qua Thiên Đạo Tông hướng chánh ma lưỡng đạo mạnh mẽ gây áp lực sau khi trưởng lão Nguyên Anh kỳ họ Trình bị trọng thương và tu sĩ Kết Đan tử vong trong trận mai phục, nhưng đối phương không thừa nhận, tranh cãi vô kết quả.","tabs":{"tienTrinh":[{"chuong":"@c0633","loai":"nhac-toi","importance":"normal","giaiDoan":"Trung gian gây áp lực thất bại","text":"Ba phái thông qua Thiên Đạo Tông gây áp lực lên chánh ma lưỡng đạo nhưng đối phương không thừa nhận, bất thành.","anchor":"thông qua Thiên Đạo Tông hướng chánh ma lưỡng đạo mạnh mẽ gây áp lực"}]},"nguon":["@c0633"]},{"id":"mo-gia","name":"Mộ gia","cn":"慕家","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"","nhanVatChinh":["Mộ Phái Linh","Trưởng lão Mộ gia"],"blurb":"Gia tộc của Mộ Phái Linh. Trưởng lão/tộc trưởng cường hoành ép Mộ Phái Linh thành thân với nam tử họ Ngôn, dọa cắt linh thạch và liên lụy người thân.","detail":"Gia tộc tu tiên có quan hệ với Lạc Vân Tông. Tộc trưởng Mộ gia định ra hôn ước hoang đường cho cháu gái Mộ Phái Linh với nam tử họ Ngôn, bất chấp ý nguyện của nàng. Dùng quyền cắt linh thạch tu luyện và đe dọa liên lụy người thân để ép buộc.","lanhDaoHienThoi":"Trưởng lão Mộ gia","thanhVien":[{"ten":"Mộ Phái Linh","chucVu":"Thành viên","tuChuong":"@c0634","trangThai":"gan-bo"}],"tabs":{"tienTrinh":[{"chuong":"@c0634","loai":"nhắc tới","importance":"normal","giaiDoan":"Ép hôn ước","trangThaiMoc":"hoạt động","text":"Tộc trưởng Mộ gia cường hoành ép Mộ Phái Linh thành thân với nam tử họ Ngôn, dọa cắt linh thạch và liên lụy người thân.","anchor":"Tộc trưởng Mộ gia, bởi vì cháu mình mang tiếng là nữ tử điêu ngoa, dĩ nhiên cường hoành định ra một cái hôn ước hoang đường"}]},"nguon":["@c0634","@c0640"]},{"id":"ngon-gia","name":"Ngôn gia","cn":"言家","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Khê Quốc","nhanVatChinh":["Ngôn sư huynh"],"blurb":"Tu tiên gia tộc không nhỏ ở Khê Quốc, định gả Mộ Phái Linh vào để song tu với Ngôn sư huynh. Hôn ước bị chủ động giải trừ sau khi Mộ Phái Linh tự xưng là thị thiếp Hàn Lập.","detail":"Gia tộc tu tiên có quy mô không nhỏ tại Khê Quốc. Tộc trưởng Ngôn gia chủ động giải trừ hôn ước với Mộ gia và truyền âm phù xin lỗi Hàn Lập, khẳng định không biết chuyện nữ tử đã thành thị thiếp.","nguon":["@c0640"]},{"id":"ma-diem-tong","name":"Ma Diễm Tông","cn":"魔焰宗","type":"tong-mon","typeLabel":"Tông môn (Ma đạo)","diaBan":"Nguyên Vũ quốc","nhanVatChinh":[],"blurb":"Một trong Ma đạo lục tông, thế lực đứng đầu Nguyên Vũ quốc. Phó gia Nguyên Vũ quốc quy phục Ma Diễm Tông, liên tục đưa đệ tử và mỹ nữ trong tộc vào tông để củng cố chỗ dựa.","detail":"Ma Diễm Tông thuộc ma đạo lục tông, là thế lực kiểm soát Nguyên Vũ quốc sau khi ma đạo xâm lấn. Phó gia Nguyên Vũ quốc nhanh chóng đầu nhập Ma Diễm Tông, được tông nâng đỡ trở thành đệ nhất gia tộc, đổi lại liên tục cống nạp đệ tử và mỹ nữ.","nguon":["@c0644"],"tabs":{"tienTrinh":[{"chuong":"@c0644","loai":"xuất hiện","importance":"normal","giaiDoan":"Giới thiệu thế lực","text":"Ma Diễm Tông được nhắc tới là tông môn trong ma đạo lục tông, kiểm soát Nguyên Vũ quốc và nhận Phó gia quy phục.","anchor":"ngay lập tức đầu nhập Ma Diễm tông trong ma đạo lục tông"}]},"nguonGoc":"Một trong sáu tông ma đạo Thiên Nam","trangThai":"đang hoạt động","capNhatToi":"@c0644"},{"id":"pho-gia-nguyen-vu","name":"Phó gia Nguyên Vũ quốc","cn":"付家","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Nguyên Vũ quốc","nhanVatChinh":[],"blurb":"Đệ nhất gia tộc Nguyên Vũ quốc hiện tại, nhanh chóng đầu nhập Ma Diễm Tông khi ma đạo xâm lấn, nhờ đó thế lực tăng vọt, áp đảo hai đại gia tộc khác.","detail":"Hơn trăm năm trước khi ma đạo xâm lấn, Phó gia Nguyên Vũ quốc nhanh chóng đầu nhập Ma Diễm Tông, không những không tổn thất mà còn vươn lên thành đệ nhất gia tộc, đồng thời liên tục đưa đệ tử và mỹ nữ trong tộc vào Ma Diễm Tông để củng cố chỗ dựa. Có quan hệ huyết mạch với Phó gia thuộc Bách Xảo Viện nhưng đã đoạn tuyệt sau khi bên Nguyên Vũ quốc đầu nhập ma đạo.","nguon":["@c0644"],"tabs":{"tienTrinh":[{"chuong":"@c0644","loai":"xuất hiện","importance":"normal","giaiDoan":"Giới thiệu gia tộc","text":"Phó gia Nguyên Vũ quốc được giới thiệu là đệ nhất gia tộc, đã đầu nhập Ma Diễm Tông khi ma đạo xâm lấn, đoạn tuyệt quan hệ với Phó gia Bách Xảo Viện.","anchor":"Bởi vậy trong đại kiếp đó Phó gia cũng không hề bị tổn thất nào"}]},"nguonGoc":"Gia tộc tu tiên lâu đời tại Nguyên Vũ quốc, có quan hệ huyết mạch với Phó gia Bách Xảo Viện","quanHe":"Quy phục Ma Diễm Tông, đoạn tuyệt với Phó gia Bách Xảo Viện","trangThai":"hưng thịnh","capNhatToi":"@c0644"},{"id":"banh-dich-song-hung","name":"Bành Dịch Song Hung","type":"bang-hoi","typeLabel":"Nhóm hung tu","diaBan":"Nguyên Vũ Quốc","nhanVatChinh":["Tu sĩ ục ịch họ La","Đại hán đầu hói"],"blurb":"Cặp hung tu tán tu gồm tu sĩ ục ịch họ La và đại hán đầu hói, có xú danh lan rộng trong giới tán tu Nguyên Vũ Quốc, chuyên nhắm người đoạt bảo.","detail":"Bành Dịch Song Hung là danh xưng chung của hai tu sĩ giấu tu vi Trúc Cơ Trung Kỳ, chuyên đóng vai yếu hơn để dụ mục tiêu rồi đánh lén đoạt tài vật. Xú danh của chúng khiến tán tu khác vừa thấy đã vội vàng tránh xa. Chúng nhắm tới Hàn Lập vì thấy hắn có phi kiếm ngự khí đỉnh cấp và túi trữ vật căng phồng, nhưng không biết hắn thực chất là tu sĩ Nguyên Anh Kỳ cải dung.","nguon":["@c0646"],"tabs":{"tienTrinh":[{"chuong":"@c0646","loai":"xuat-hien","importance":"normal","trangThaiMoc":"Đang phục kích Hàn Lập","giaiDoan":"Bàn mưu đoạt bảo","text":"Lập kế giết Hàn Lập đoạt bảo, bố trí trận pháp vây địch trong tiểu cốc, dẫn hắn tới tiểu sơn phục kích nhưng bị vạch mặt.","anchor":"dĩ nhiên gặp phải Bành Dịch Song Hung chúng ta, hiển nhiên không thể bỏ qua"}]}},{"id":"dam-gia","name":"Đàm Gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Nguyên Vũ Quốc","nhanVatChinh":[],"blurb":"Gia tộc tu tiên tại Nguyên Vũ Quốc, kẻ thù tối thù địch của Phó Gia. Từng bị Phó Gia giết tu sĩ chủ lực chống ma đạo, nay tu sĩ cao cấp suy giảm, ẩn nấp hận thấu xương, có khả năng liên thủ với Hỗ Gia báo thù.","detail":"Từng tranh hơn thua với Phó Gia, bị Phó Gia ra tay giết tu sĩ chủ lực để lấy lòng Ma Diễm Môn. Hiện tu sĩ cao cấp không còn bao nhiêu, bị chèn ép phải ẩn nấp. Phó Gia nghi ngờ Đàm Gia có thể liên thủ với Hỗ Gia hoặc liên hợp tiểu phái đánh bất ngờ nhân dịp lễ mừng thọ.","nguon":["@c0649"]},{"id":"ho-gia","name":"Hỗ Gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Nguyên Vũ Quốc","nhanVatChinh":[],"blurb":"Gia tộc tu tiên tại Nguyên Vũ Quốc, cùng Đàm Gia là kẻ thù nhất của Phó Gia. Cùng cảnh ngộ suy tàn sau khi bị Phó Gia chèn ép, có khả năng liên thủ báo thù.","detail":"Cùng Đàm Gia bị Phó Gia ra tay giết tu sĩ chủ lực chống ma đạo để lấy lòng Ma Diễm Môn, nay hận thấu xương, tu sĩ cao cấp suy giảm, có thể liên thủ đánh bất ngờ nhân dịp thọ.","nguon":["@c0649"]},{"id":"toai-hon-mon","name":"Toái Hồn Môn","cn":"","type":"phan-he","typeLabel":"Phân hệ","diaBan":"Yểm Nguyệt Tông, có phân đàn tại Việt Quốc","nhanVatChinh":["Toái Hồn Chân Nhân","Tam sư huynh Toái Hồn Môn","Ngũ sư muội Toái Hồn Môn","Khuyết sư đệ","Vu Hồng"],"blurb":"Toái Hồn Môn là phân hệ trực thuộc Quỷ Linh Môn, do Toái Hồn Chân Nhân đứng đầu, hoạt động ẩn mình bên trong Yểm Nguyệt Tông. Tổ chức có ít nhất bảy đệ tử, vận hành theo hệ thống phân đàn với kỷ luật khắc nghiệt.","detail":"Toái Hồn Môn là một phân hệ nằm trong hệ thống Quỷ Linh Môn, đặt sào huyệt tại phòng bí mật bên trong Yểm Nguyệt Tông, hoạt động dưới danh nghĩa tông môn mẹ. Đứng đầu là Toái Hồn Chân Nhân, dưới trướng có ít nhất bảy đệ tử được xưng theo thứ tự sư huynh đệ. Tổ chức phân chia thành nhiều phân đàn, mỗi phân đàn có Đàn chủ riêng, trong đó Nhạc phân đàn là một cấp được nhắc tới. Kỷ luật nội bộ rất nghiêm khắc: Nhị sư huynh và Thất sư đệ từng bị xử phạt vì không hoàn thành nhiệm vụ. Lục sư đệ Vu Hồng bị Hàn Lập giết chết; Toái Hồn Chân Nhân cảm ứng được linh quang trên bổn mạng lệnh bài của Vu Hồng tắt đi, liền triệu tập ba đệ tử Kết Đan Kỳ còn lại để truy tìm hung thủ (@c0656).","nguonGoc":"Phân hệ của Quỷ Linh Môn","lanhDaoHienThoi":"Toái Hồn Chân Nhân","thanhVien":[{"ten":"Toái Hồn Chân Nhân","chucVu":"Chưởng môn","tuChuong":"@c0656","trangThai":"song"},{"ten":"Tam sư huynh Toái Hồn Môn","chucVu":"Tam đệ tử","tuChuong":"@c0656","trangThai":"song"},{"ten":"Ngũ sư muội Toái Hồn Môn","chucVu":"Ngũ đệ tử","tuChuong":"@c0656","trangThai":"song"},{"ten":"Khuyết sư đệ","chucVu":"Đệ tử","tuChuong":"@c0656","trangThai":"song"},{"ten":"Vu Hồng","chucVu":"Lục đệ tử","tuChuong":"@c0656","trangThai":"tu-vong"}],"tabs":{"tienTrinh":[{"chuong":"@c0656","loai":"xuất hiện","importance":"major","giaiDoan":"Ra mắt sau khi Lục sư đệ bị giết","trangThaiMoc":"Hoạt động","text":"Toái Hồn Chân Nhân cảm ứng bổn mạng lệnh bài của Lục sư đệ Vu Hồng tắt linh quang, triệu tập ba đệ tử Kết Đan Kỳ ra lệnh truy tìm hung thủ. Ba người phát hiện động phủ cũ của Hàn Lập tại Thái Nhạc Sơn chỉ còn hố to.","anchor":"đã là đệ tử của Toái Hồn Môn thì không thể nào chết không minh bạch được"}]},"capNhatToi":"@c0656","nguon":["@c0656"],"dacDiem":"Tổ chức ẩn mình trong tông phái khác, vận hành theo hệ thống phân đàn riêng biệt, kỷ luật nội bộ khắc nghiệt.","congNang":["Bổn mạng lệnh bài của đệ tử được Toái Hồn Chân Nhân cảm ứng từ xa; khi đệ tử tử vong, linh quang trên lệnh bài tắt, chưởng môn lập tức biết tin (@c0656)"]},{"id":"han-gia-kinh-chau","name":"Hàn gia Kính Châu","cn":"韩家","type":"gia-toc","typeLabel":"Gia tộc phàm nhân","diaBan":"Kính Châu, Ngũ Lý Câu (cũ)","nhanVatChinh":["Hàn Lập","Hàn thị lang"],"blurb":"Hàn gia Kính Châu là gia tộc phàm nhân gốc ở Ngũ Lý Câu, quật khởi chưa đầy trăm năm nhờ con cháu bên ngoại thi đậu làm quan lớn, tới nay thanh thế đã ngang hàng hai nhà Phạm, Lý — trở thành một trong tam đại thế gia tại Kính Châu.","detail":"Vốn là một gia tộc phàm nhân bình thường tại Ngũ Lý Câu — quê cũ của Hàn Lập, Hàn gia dần tích lũy thanh thế nhờ một thế hệ con cháu bên ngoại làm quan lớn, trong khoảng chưa đầy trăm năm đã vươn lên ngang hàng hai gia tộc lâu đời là nhà Phạm và nhà Lý, hình thành cục diện tam đại thế gia Kính Châu (@c0658). Hàn gia đã dời khỏi Ngũ Lý Câu hơn mười dặm từ hơn mười năm trước, xây dựng cơ nghiệp mới. Trong tộc có Hàn Gia Từ thờ phụng mấy trăm linh vị cùng bản chép tay gia tổ, và từng tổ chức tế tổ long trọng đến mức Châu lệnh đại nhân đích thân tới bái hội, đồng thời phát tín hàm triệu tộc nhân các nơi quay về.","nguonGoc":"Gia tộc phàm nhân tại Ngũ Lý Câu, quật khởi nhờ một thế hệ con cháu bên ngoại làm quan lớn, tích lũy dần trong chưa đầy trăm năm.","quyMo":"Tam đại thế gia Kính Châu, ngang nhà Phạm và nhà Lý","trangThai":"hưng thịnh","capNhatToi":"@c0658","tabs":{"tienTrinh":[{"chuong":"@c0658","loai":"nhắc tới","importance":"major","giaiDoan":"Quật khởi thành tam đại thế gia Kính Châu","text":"Hai nho sinh tửu lâu bàn luận Hàn gia đã phát triển nhanh chưa đầy trăm năm, thanh thế ngang hai nhà Phạm, Lý, tổ chức tế tổ long trọng được Châu lệnh bái hội.","anchor":"Hàn gia phát triển rất nhanh sau này cũng như hai nhà Phạm, Lý trở thành tam đại thế gia ở Kính Châu này đây"}]},"nguon":["@c0658"],"dacDiem":"Gia tộc phàm nhân quật khởi cực nhanh — chưa đầy trăm năm từ hương thôn nhỏ đã chen vào hàng tam đại thế gia Kính Châu, nhờ thế lực quan trường bên ngoại mà tích lũy thanh thế."},{"id":"le-gia","name":"Lệ gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Không rõ","nhanVatChinh":["Lệ Phi Vũ","Lệ Phong"],"blurb":"Gia tộc phàm nhân, hậu duệ Lệ Phi Vũ. Đã thông gia với Hàn gia qua con gái Lệ Phi Vũ. Có cơ nghiệp đồ sộ truyền đời.","detail":"Gia tộc phàm nhân do Lệ Phi Vũ gây dựng. Con gái Lệ Phi Vũ kết thông gia với Hàn gia, từ đó hai nhà gắn bó. Đại hán râu quai nón (Lệ Phong) là hậu nhân hiện tại, có sức mạnh thể chất đáng kể nhưng vẫn là phàm nhân.","nguon":["@c0659"]},{"id":"thien-nhat-hoi","name":"Thiên Nhất Hội","cn":"","type":"the-luc","typeLabel":"Thế lực","diaBan":"Lam Châu","nhanVatChinh":[],"blurb":"Thế lực tân quật khởi thay thế Ngũ Sắc Môn ở Lam Châu.","detail":"Thế lực mới nổi ở Lam Châu, thay thế vị trí của Ngũ Sắc Môn sau khi tông môn này sụp đổ.","nguon":["@c0661"]},{"id":"lien-minh-chin-nuoc","name":"Liên minh chín nước","cn":"九国联盟","type":"lien-minh","typeLabel":"Liên minh","diaBan":"Phía bắc Thiên Nam đế quốc","nhanVatChinh":["Cửu Quốc Minh"],"blurb":"Liên minh của chín nước tu tiên tại Thiên Nam, tổng đàn là tòa thành tu sĩ duy nhất Thiên Nam, nơi tổ chức Giao dịch hội. Ngoài Cửu Quốc Minh lão quái còn có sáu bảy tu sĩ Nguyên Anh Trung Kỳ trấn giữ.","detail":"Tổng đàn liên minh chín nước tọa lạc phía bắc Thiên Nam đế quốc, là tòa thâm sơn do thiên nhiên tạo thành, đồng thời là tòa thành tu sĩ duy nhất tại Thiên Nam. Ngoài Cửu Quốc Minh lão quái, còn có thêm sáu bảy tu sĩ Nguyên Anh Trung Kỳ khác trấn giữ. Liên minh tổ chức Giao dịch hội định kỳ, mở địa trận Thượng Nguyên Diệt Quang trận bảo vệ khu vực, phòng đấu giá do Cửu Quốc Minh làm nhà cái tiếp nhận tài liệu trân quý.","nguonGoc":"Liên minh của chín nước tu tiên Thiên Nam","lanhDaoHienThoi":"Cửu Quốc Minh","quyMo":"Nhiều Nguyên Anh Trung Kỳ trấn giữ","tabs":{"tienTrinh":[{"chuong":"@c0670","loai":"nhắc tới","importance":"normal","giaiDoan":"Tổ chức Giao dịch hội","text":"Tổng đàn liên minh chín nước mở Giao dịch hội, kích hoạt Thượng Nguyên Diệt Quang trận, phòng đấu giá do Cửu Quốc Minh làm nhà cái bắt đầu tiếp nhận tài liệu.","anchor":"Nguyên Anh Trung Kỳ ngoài Cửu Quốc Minh lão quái còn có thêm sáu bảy người khác"}]},"nguon":["@c0670"]},{"id":"ton-gia","name":"Tôn gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Thiên Nam","nhanVatChinh":["Tôn Nhị Cẩu","Tôn Hỏa"],"blurb":"Gia tộc hậu nhân của Tôn Nhị Cẩu, năm xưa Tôn Nhị Cẩu thề dòng tộc sẽ nhận Hàn Lập làm chủ nhưng chưa từng chính thức thực hiện vì Hàn Lập vắng mặt ở Thiên Nam.","detail":"Tôn Hỏa là huyền tôn đời thứ bảy của Tôn Nhị Cẩu. Dòng tộc mang lời thề nhận Hàn Lập làm chủ nhân nhưng chưa bao giờ chính thức thực hiện do Hàn Lập không ở Thiên Nam. Hàn Lập đưa ra hai lựa chọn cho Tôn Hỏa: cắt đứt quan hệ hoặc kế thừa lời thề.","nguon":["@c0680"]},{"id":"nguoi-mo-lan","name":"Người Mộ Lan","cn":"慕蘭人","type":"chung-toc","typeLabel":"Chủng tộc","diaBan":"Mộ Lan hư không thảo nguyên và khu vực biên giới Thiên Nam","nhanVatChinh":[],"blurb":"Người Mộ Lan là chủng tộc bản địa Mộ Lan thảo nguyên, sở hữu hệ thống tu luyện riêng biệt dựa trên pháp sĩ thay vì tu sĩ. Từng đình chiến với tu sĩ Thiên Nam hơn trăm năm, nay tái khởi chiến tranh bằng đội tiên phong mang theo bão cát quy mô khổng lồ, bên trong ẩn tàng lực lượng pháp sĩ hùng hậu.","detail":"Người Mộ Lan là chủng tộc sinh sống tại Mộ Lan thảo nguyên, có hệ thống tu luyện hoàn toàn khác biệt so với tu sĩ thông thường — những người tu luyện trong tộc được gọi là pháp sĩ. Hơn trăm năm trước, Người Mộ Lan từng giao tranh với tu sĩ Thiên Nam rồi đình chiến. Tới thời điểm @c0686, Người Mộ Lan chính thức khai chiến trở lại: đội tiên phong xuất hiện kèm theo bão cát Phong Linh Thuật có quy mô gấp trăm ngàn lần bình thường, bên trong ẩn nặc nhiều pháp sĩ di chuyển trong các phong trụ. Lực lượng pháp sĩ của họ có khả năng thi triển cấm chế để ám toán nhóm tu sĩ Nguyên Anh Kỳ, và trong hàng ngũ có thể tồn tại người ngang tu vi Nguyên Anh Kỳ, cho thấy thực lực quân sự không hề thua kém giới tu sĩ Thiên Nam.","nguonGoc":"Chủng tộc bản địa Mộ Lan thảo nguyên","trangThai":"Khai chiến","tabs":{"tienTrinh":[{"chuong":"@c0686","loai":"khai chiến","importance":"major","giaiDoan":"Đội tiên phong xuất hiện, mở màn chiến tranh mới","trangThaiMoc":"Khai chiến","text":"Đội tiên phong Người Mộ Lan xuất hiện với bão cát Phong Linh Thuật quy mô gấp trăm ngàn lần bình thường, bên trong ẩn tàng nhiều pháp sĩ. Chiến tranh mới sắp bắt đầu sau hơn trăm năm đình chiến.","anchor":"Trăm năm hơn thời gian cũng không sai biệt lắm. Đủ có thể làm cho Người Mộ Lan nghỉ ngơi dưỡng sức xong"}]},"capNhatToi":"@c0686","nguon":["@c0686"],"uyLuc":"Đội tiên phong triển khai bão cát Phong Linh Thuật quy mô gấp trăm ngàn lần bình thường, bên trong ẩn tàng nhiều pháp sĩ có thể ngang tu vi Nguyên Anh Kỳ, đủ sức thi triển cấm chế ám toán tu sĩ Nguyên Anh Kỳ @c0686.","dacDiem":"Hệ thống tu luyện riêng biệt dùng pháp sĩ thay vì tu sĩ; linh thuật gắn liền với phong sa (gió và cát); di chuyển chiến đấu bằng phong trụ ẩn trong bão cát.","congNang":["Phong Linh Thuật — linh thuật đặc trưng có thể tạo bão cát ngăn thần thức dò xét, quy mô khi khai chiến gấp trăm ngàn lần bình thường @c0686","Pháp sĩ ẩn nặc trong các phong trụ di chuyển bên trong bão cát @c0686","Thi triển cấm chế ám toán nhóm tu sĩ Nguyên Anh Kỳ @c0686"]},{"id":"hoang-sa-bo","name":"Hoàng Sa Bộ","cn":"黃沙部","type":"bo-toc","typeLabel":"Bộ tộc Mộ Lan","diaBan":"Mộ Lan thảo nguyên","nhanVatChinh":["Đại Thượng Sư (Hoàng Sa Bộ)","Pháp sĩ bạch quang (Hoàng Sa Bộ)","Pháp sĩ điện hồ (Hoàng Sa Bộ)"],"blurb":"Hoàng Sa Bộ là một trong mười đại bộ tộc Mộ Lan, từng bố trí ảo trận cát vàng nhằm vây khốn nhóm tu sĩ Hàn Lập nhưng thất bại do uy lực quá yếu trước đám Nguyên Anh.","detail":"Hoàng Sa Bộ là bộ tộc thuộc liên quân mười đại bộ tộc Mộ Lan. Trong cuộc giao tranh với nhóm tu sĩ Hàn Lập, bộ tộc này đã triển khai ảo trận cát vàng để vây hãm đối phương, tuy nhiên cấm chế của trận pháp bị phá giải dễ dàng, cho thấy trình độ trận pháp không đủ sức uy hiếp tu sĩ cấp Nguyên Anh. Bộ tộc có Đại Thượng Sư chỉ huy tại trận nhưng đã từ chối sử dụng trấn tộc thánh khí trong tình huống này.","lanhDaoHienThoi":"Đại Thượng Sư (Hoàng Sa Bộ)","quyMo":"Đại bộ tộc trong liên quân mười đại bộ tộc","trangThai":"Hưng thịnh, dẫn đầu liên quân","quanHe":"Không hòa thuận với Thiên Phong Bộ; liên minh với chín bộ tộc khác","tranPhai":"Ma Trần Phiên (trấn tộc thánh khí, 36 can)","thanhVien":[{"ten":"Đại Thượng Sư (Hoàng Sa Bộ)","chucVu":"Đại Thượng Sư (thủ lĩnh)","tuChuong":"@c0687","trangThai":"hoat-dong"},{"ten":"Pháp sĩ bạch quang (Hoàng Sa Bộ)","chucVu":"Thượng Sư","tuChuong":"@c0687","trangThai":"hoat-dong"},{"ten":"Pháp sĩ điện hồ (Hoàng Sa Bộ)","chucVu":"Pháp sĩ","tuChuong":"@c0687","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0687","loai":"khai chiến","importance":"major","trangThaiMoc":"Vây đám tu sĩ thất bại","text":"Bố trí ảo trận cát vàng vây nhóm tu sĩ Hàn Lập nhưng cấm chế bị phá dễ dàng. Đại Thượng Sư từ chối dùng trấn tộc thánh khí Ma Trần Phiên, quyết định chờ quân chủ lực đến. Hé lộ vị trí dẫn đầu liên quân mười đại bộ tộc nhờ Ma Trần Phiên và mâu thuẫn nội bộ với Thiên Phong Bộ.","anchor":"chúng ta dựa vào cái gì yên ổn ngồi ở vị trí dẫn đầu liên quân mười đại bộ tộc"}]},"nguon":["@c0687"],"dacDiem":"Sở trường dùng ảo trận cát vàng, tuy nhiên uy lực trận pháp không đủ uy hiếp tu sĩ cấp Nguyên Anh.","congNang":["Bố trí ảo trận cát vàng để vây khốn đối thủ @c0687"]},{"id":"thien-phong-bo","name":"Thiên Phong Bộ","cn":"天風部","type":"bo-toc","typeLabel":"Bộ tộc Mộ Lan","diaBan":"Mộ Lan thảo nguyên","nhanVatChinh":["Mục Thượng Sư (Thiên Phong Bộ)"],"blurb":"Bộ tộc Mộ Lan sở hữu trấn tộc bảo vật Ngự Phong Xa có tốc độ kinh khủng. Mục Thượng Sư tạm chỉ huy tiên phong liên quân, vốn không hòa thuận với Hoàng Sa Bộ.","detail":"Bộ tộc Mộ Lan khác trong liên quân mười đại bộ tộc, do Mục Thượng Sư lãnh đạo. Sở hữu trấn tộc bảo vật Ngự Phong Xa có tốc độ cực cao. Vốn không hòa thuận với Hoàng Sa Bộ. Mục Thượng Sư đưa tin khiến Hoàng Sa Bộ vây nhóm tu sĩ rồi đi liên lạc bộ lạc khác, bị nghi mượn cơ trả thù.","lanhDaoHienThoi":"Mục Thượng Sư (Thiên Phong Bộ)","trangThai":"Hoạt động trong liên quân","quanHe":"Không hòa thuận với Hoàng Sa Bộ","tranPhai":"Ngự Phong Xa (trấn tộc bảo vật)","thanhVien":[{"ten":"Mục Thượng Sư (Thiên Phong Bộ)","chucVu":"Thượng Sư (thủ lĩnh)","tuChuong":"@c0687","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0687","loai":"nhắc tới","importance":"normal","trangThaiMoc":"Bị nghi ngờ ý đồ","text":"Mục Thượng Sư đưa tin khiến Hoàng Sa Bộ vây nhóm tu sĩ rồi đi liên lạc bộ lạc khác, bị Đại Thượng Sư nghi có tâm bất lương mượn cơ trả thù.","anchor":"hai bộ lạc chúng ta nguyên bản vốn không thế nào thực sự hòa thuận"}]},"nguon":["@c0687"]},{"id":"lien-quan-muoi-dai-bo-toc-mo-lan","name":"Liên quân mười đại bộ tộc (Mộ Lan)","cn":"","type":"lien-minh","typeLabel":"Liên minh bộ tộc","diaBan":"Mộ Lan thảo nguyên","nhanVatChinh":[],"blurb":"Liên minh mười đại bộ tộc Mộ Lan, hiện do Hoàng Sa Bộ dẫn đầu. Quân chủ lực đang tập hợp, chưa tới chiến trường.","detail":"Liên quân gồm mười đại bộ tộc Mộ Lan cùng nhiều tiểu bộ tộc, hiện do Hoàng Sa Bộ dẫn đầu nhờ trấn tộc thánh khí Ma Trần Phiên. Quân chủ lực đang trên đường tới.","quyMo":"Mười đại bộ tộc và nhiều tiểu bộ tộc","trangThai":"Đang tập hợp lực lượng","tabs":{"tienTrinh":[{"chuong":"@c0687","loai":"nhắc tới","importance":"normal","trangThaiMoc":"Được nhắc tới, quân chủ lực chưa đến","text":"Đại Thượng Sư nhắc tới liên quân mười đại bộ tộc, Hoàng Sa Bộ đang dẫn đầu, chờ quân chủ lực đến thì đại thắng.","anchor":"chúng ta dựa vào cái gì yên ổn ngồi ở vị trí dẫn đầu liên quân mười đại bộ tộc"}]},"nguon":["@c0687"]},{"id":"ma-mon","name":"Ma Môn","type":"the-luc","typeLabel":"Thế lực","diaBan":"Không rõ","nhanVatChinh":["Vương Thiên Cổ","Yến Như Yên","Vương Thiền"],"blurb":"Thế lực đối lập với Thiên Đạo Minh. Hàn Lập khẳng định quan hệ hai bên là thù địch, không thể hóa giải.","detail":"Thế lực mà Vương Thiên Cổ, Yến Như Yên và Vương Thiền thuộc về. Hàn Lập tự xưng thuộc Thiên Đạo Minh, khẳng định Ma Môn và Thiên Đạo Minh vốn là quan hệ thù địch, cự tuyệt đề nghị hóa giải cừu oán từ Yến Như Yên.","nguon":["@c0697"]},{"id":"thien-cuc-mon","name":"Thiên Cực Môn","cn":"天极门","type":"tong-mon","typeLabel":"Tông môn","diaBan":"","nhanVatChinh":[],"blurb":"Thế lực chính đạo, có mấy vị trưởng lão đã lén kết giao với Nam Lũng Hầu, Nam Lũng Hầu có ý gia nhập và trợ giúp Thiên Cực Môn vào Trụy Ma Cốc lấy bảo.","detail":"Thế lực chính đạo được lão giả họ Vân nhắc tới. Nam Lũng Hầu lén kết giao với mấy vị trưởng lão Thiên Cực Môn, có ý gia nhập tông môn này và trợ giúp chính đạo vào Trụy Ma Cốc lấy bảo. Đây là lý do lão giả họ Vân (Trưởng lão Quỷ Linh Môn) quyết hạ độc thủ đối với Nam Lũng Hầu, nhằm ngăn thế lực chính đạo bành trướng.","nguon":["@c0701"],"tabs":{"tienTrinh":[{"chuong":"@c0701","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị tiết lộ đang lôi kéo Nam Lũng Hầu","text":"Lão giả họ Vân tiết lộ Nam Lũng Hầu lén kết giao trưởng lão Thiên Cực Môn, có ý gia nhập và trợ giúp chính đạo vào Trụy Ma Cốc lấy bảo.","anchor":"hắn lại len lén kết giao với mấy vị trưởng lão Thiên Cực Môn, cũng có ý gia nhập tông môn này"}]}},{"id":"hoa-y-mon","name":"Hóa Ý Môn","cn":"化意门","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Thiên Nam","nhanVatChinh":["Ngụy Ly Thần"],"blurb":"Tông môn tu tiên ở Thiên Nam, có trưởng lão Ngụy Ly Thần là tu sĩ Nguyên Anh kỳ, kỳ tài trong ba trăm năm kết thành Nguyên Anh.","detail":"Trưởng lão Ngụy Ly Thần trong ba trăm năm đã kết thành Nguyên Anh, thần thông thâm sâu khó lường, được xem là kỳ tài tu tiên Thiên Nam. Sắp tổ chức song tu đại điển liên tông giữa Ngụy Ly Thần và Nam Cung Uyển (trưởng lão Yểm Nguyệt Tông).","tabs":{"tienTrinh":[{"chuong":"@c0707","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nhắc đến lần đầu","text":"Trưởng lão Ngụy Ly Thần là tu sĩ Nguyên Anh kỳ, kỳ tài Thiên Nam, sắp cùng Nam Cung Uyển cử hành song tu đại điển.","anchor":"vị trưởng lão Ngụy Ly Thần của Hóa Ý môn trong ba trăm năm đã kết thành Nguyên Anh"},{"chuong":"@c0708","loai":"nhac-toi","importance":"normal","giaiDoan":"Được nhắc đến như thế lực cản đường Hàn Lập","text":"Được nhắc là một trong hai đại tông phái lớn nhất Cửu Quốc Minh, có bốn năm trưởng lão Nguyên Anh kỳ. Hàn Lập cân nhắc ám sát Ngụy Ly Thần nhưng đánh giá Hóa Ý Môn quá mạnh.","anchor":"Hóa Ý Môn chẳng phải là loại tiểu tông tiểu phái gì mà chính là một trong hai đại tông phái lớn nhất của Cửu Quốc Minh"},{"chuong":"@c0712","loai":"nhắc tới","importance":"normal","giaiDoan":"Lần đầu lộ diện","text":"Được nhắc đến: Ngụy Ly Thần là trưởng lão Hóa Ý Môn, nếu cưới Nam Cung Uyển sẽ thoát ly tông môn.","anchor":"Ngụy Ly Thần sau khi lấy thiếp sẽ nguyện ý thoát ly Hóa Ý Môn, gia nhập Yểm Nguyệt Tông"}]},"thanhVien":[{"ten":"Ngụy Ly Thần","chucVu":"Trưởng lão","tuChuong":"@c0707","trangThai":"dang-o"}],"nguon":["@c0707","@c0708","@c0712"],"trangThai":"hien-dien"},{"id":"vien-gia","name":"Viên gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Phía Bắc Bắc Lương Quốc","nhanVatChinh":["Viên Khôn"],"blurb":"Gia tộc tu tiên trung đẳng kỳ cựu ở phía Bắc Bắc Lương Quốc, từng trợ giúp lục phái và Yểm Nguyệt Tông đặt chân tại đây.","detail":"Viên gia là gia tộc tu tiên trung đẳng kỳ cựu ở phía Bắc Bắc Lương Quốc. Từng trợ giúp lục phái và Yểm Nguyệt Tông khi họ mới tới Bắc Lương Quốc, nhờ đó Yểm Nguyệt Tông hứa hẹn tưởng thưởng bồi thường. Viên Khôn là cháu ruột gia chủ, được giao làm quản sự trong Yểm Nguyệt Tông.","quyMo":"Gia tộc tu tiên trung đẳng","trangThai":"hien-dien","tabs":{"tienTrinh":[{"chuong":"@c0708","loai":"nhac-toi","importance":"bridge","giaiDoan":"Được giới thiệu lai lịch","text":"Được giới thiệu là gia tộc tu tiên trung đẳng kỳ cựu từng trợ giúp lục phái đặt chân Bắc Lương Quốc.","anchor":"phía Bắc của Bắc Lương Quốc có một gia tộc tu tiên trung đẳng kỳ cựu"}]},"capNhatToi":"@c0708","nguon":["@c0708"]},{"id":"mo-lan-phap-si","name":"Mộ Lan pháp sĩ","cn":"穆兰法士","type":"the-luc","typeLabel":"Thế lực","diaBan":"Phong Nguyên Quốc","nhanVatChinh":["Trọng Thần Sư"],"blurb":"Mộ Lan pháp sĩ là thế lực pháp sĩ thuộc Phong Nguyên Quốc, khai chiến tại biên giới Ngu Quốc. Nhờ sở hữu man hoang cự thú từ nguồn gốc bí ẩn, họ đại thắng quân chủ lực Cửu Quốc Minh liên tiếp ba trận, buộc phía Cửu Quốc Minh phải điều động lực lượng cấp Nguyên Anh đề phòng.","detail":"Đại quân Mộ Lan pháp sĩ xuất thân từ Phong Nguyên Quốc, mở cuộc đại chiến tại biên giới Ngu Quốc chống lại liên minh Cửu Quốc Minh. Không rõ bằng cách nào, thế lực này kiếm được một số man hoang cự thú — loại hung thú cực kỳ khó đối phó — khiến tu sĩ phía Cửu Quốc Minh không có biện pháp ứng phó hữu hiệu, liên tục thảm bại trong ba trận liên tiếp (@c0718). Thế tiến công của Mộ Lan pháp sĩ cực kỳ hung hãn. Tình hình nghiêm trọng đến mức phía Cửu Quốc Minh phải cảnh giác trước khả năng đối phương có tu sĩ cấp Nguyên Anh Hậu Kỳ tham chiến; Trọng thần sư — một trong ba Thần sư cao cấp của Cửu Quốc Minh — đã từ bỏ việc truy đuổi Hàn Lập để quay về hội hợp cùng hai Thần sư còn lại nhằm đề phòng mối đe dọa này (@c0744).","nguon":["@c0718","@c0744"],"tabs":{"tienTrinh":[{"chuong":"@c0718","loai":"khai chiến","importance":"major","trangThaiMoc":"thắng thế","giaiDoan":"Đại thắng Cửu Quốc Minh","text":"Dùng man hoang cự thú từ nguồn bí ẩn đánh bại quân chủ lực Cửu Quốc Minh liên tiếp ba trận, buộc đối phương phải phát hội minh cầu viện.","anchor":"Mộ Lan pháp sĩ không biết kiếm được một số man hoang cự thú từ đâu, tu sĩ Cửu Quốc Minh ứng phó không được nên mới liên tục thảm bại"},{"chuong":"@c0744","loai":"nhắc tới","importance":"normal","giaiDoan":"Thần sư hội hợp chuẩn bị đại chiến","text":"Trọng thần sư từ bỏ truy đuổi Hàn Lập, quay về hội hợp hai Thần sư còn lại để đề phòng tu sĩ Nguyên Anh Hậu Kỳ Thiên Nam. Đại chiến sinh tử giữa tu sĩ và pháp sĩ sắp bùng phát.","anchor":"vài tên tu sĩ Nguyên Anh hậu kỳ của Thiên Nam đồng dạng sẽ không ngồi yên"}]},"aliases":["Pháp sĩ Mộ Lan"],"thanhVien":[{"ten":"Trọng Thần Sư","chucVu":"Thần sư","tuChuong":"@c0744","trangThai":"hoat-dong"}],"uyLuc":"Dùng man hoang cự thú đánh bại quân chủ lực Cửu Quốc Minh liên tiếp ba trận, buộc đối phương phải huy động cấp Thần sư hội hợp đề phòng (@c0718, @c0744).","dacDiem":"Sở hữu man hoang cự thú từ nguồn gốc bí ẩn, thế tiến công cực hung hãn, đủ sức uy hiếp toàn bộ mặt trận biên giới Ngu Quốc.","congNang":["Sử dụng man hoang cự thú trong chiến trận, khiến tu sĩ đối phương không thể ứng phó, liên tiếp đại thắng ba trận (@c0718)","Thế lực đủ mạnh để buộc phía Cửu Quốc Minh phải tập trung cả ba Thần sư đề phòng, nghi ngờ có tu sĩ Nguyên Anh Hậu Kỳ tham chiến (@c0744)"]},{"id":"boi-diep-tong","name":"Bối Diệp Tông","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Cửu Quốc Minh, Thiên Nam","nhanVatChinh":["Ngô Bằng"],"blurb":"Một trong hai đại phái hàng đầu Cửu Quốc Minh, tông chủ là Ngô Bằng (Nguyên Anh trung kỳ), đang chủ sự liên minh chống Mộ Lan.","detail":"Bối Diệp Tông cùng Hóa Ý Môn là hai đại phái hàng đầu của Cửu Quốc Minh. Tông chủ Ngô Bằng đang dẫn đầu liên minh tu sĩ Thiên Nam chống lại cuộc xâm lấn của pháp sĩ Mộ Lan.","lanhDaoHienThoi":"Ngô Bằng","thanhVien":[{"ten":"Ngô Bằng","chucVu":"Tông chủ","tuChuong":"@c0720","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0720","loai":"xuat-hien","importance":"normal","giaiDoan":"Lộ diện tại hội nghị điện nghị","text":"Được giới thiệu là một trong hai đại phái hàng đầu Cửu Quốc Minh, tông chủ Ngô Bằng chủ trì hội nghị chống Mộ Lan.","anchor":"Bối Diệp Tông cùng Hóa Ý Môn là hai đại phái hàng đầu của Cửu Quốc Minh"}]},"nguon":["@c0720"]},{"id":"am-anh-tong","name":"Ám Ảnh Tông","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Thiên Nam","nhanVatChinh":["Hoàn đạo hữu"],"blurb":"Tông môn Thiên Nam, Hoàn đạo hữu (Nguyên Anh tu sĩ) thuộc tông này vừa tử chiến trong chiến tranh Mộ Lan.","detail":"Ám Ảnh Tông có Nguyên Anh tu sĩ Hoàn đạo hữu, vị này tử chiến trong trận đại bại, là Nguyên Anh thứ hai chết trận kể từ khi khai chiến.","thanhVien":[{"ten":"Hoàn đạo hữu","chucVu":"Nguyên Anh tu sĩ","tuChuong":"@c0720","trangThai":"tu-vong"}],"tabs":{"tienTrinh":[{"chuong":"@c0720","loai":"nhan-toi","importance":"normal","giaiDoan":"Tổn thất Nguyên Anh tu sĩ","text":"Hoàn đạo hữu (Nguyên Anh tu sĩ) tử chiến, là vị Nguyên Anh thứ hai chết trận kể từ khi khai chiến với Mộ Lan.","anchor":"thậm chí Ám Ảnh Tông Hoàn đạo hữu còn tử chiến trong trận này"}]},"nguon":["@c0720"]},{"id":"thien-thai-coc","name":"Thiên Thai Cốc","cn":"","type":"cu-diem","typeLabel":"Cứ điểm phòng thủ","diaBan":"Tuyến trước phòng thủ Thiên Nam","nhanVatChinh":["Bặc Vân Hạc"],"blurb":"Thiên Thai Cốc là cứ điểm phòng thủ tuyến trước do Bặc Vân Hạc (Nguyên Anh Kỳ) chủ trì, dựa vào đại trận phòng ngự để chống đỡ đại quân Mộ Lan. Cứ điểm đã thất thủ khi phe Mộ Lan triển khai thượng cổ cự thú mặc chiến giáp được gia trì cổ quái cấm pháp phá vỡ đại trận, tu sĩ sống sót rút về Hoàng Long Sơn.","detail":"Thiên Thai Cốc đóng vai trò cứ điểm phòng thủ tuyến trước, lấy đại trận làm nòng cốt phòng ngự, do tu sĩ Nguyên Anh Kỳ Bặc Vân Hạc chủ trì trấn thủ. Trong đợt tấn công của đại quân Mộ Lan, pháp sĩ Mộ Lan mang theo thượng cổ cự thú — loại cự thú da dày thịt béo, được khoác chiến giáp gia trì cổ quái cấm pháp — xông vào phá trận. Đại trận phòng thủ sớm muộn không chống nổi và bị phá vỡ. Bặc Vân Hạc tuy có đủ sức đả thương cự thú nhưng bị hai Đại Thượng Sư phía Mộ Lan liên thủ kìm chân, không thể chi viện. Thiên Thai Cốc thất thủ, các tu sĩ sống sót phải triệt thoái về Hoàng Long Sơn (@c0728).","trangThai":"thất thủ","lanhDaoHienThoi":"Bặc Vân Hạc","thanhVien":[{"ten":"Bặc Vân Hạc","chucVu":"Chủ trì","tuChuong":"@c0728","trangThai":"da-roi"}],"tabs":{"tienTrinh":[{"chuong":"@c0728","loai":"diet","importance":"major","giaiDoan":"Thất thủ trước đại quân Mộ Lan","trangThaiMoc":"thất thủ","text":"Đại trận bị thượng cổ cự thú mặc chiến giáp phá vỡ. Bặc Vân Hạc bị hai Đại Thượng Sư liên thủ kìm chân. Tu sĩ sống sót rút về Hoàng Long Sơn nhờ lão giả họ Mã tiếp ứng.","anchor":"Lục đạo hữu nơi này có viện quân của Mã đạo hữu thì hẳn là sẽ không giống như Thiên Thai Cốc dễ dàng mất như vậy"}]},"capNhatToi":"@c0728","nguon":["@c0728"],"dacDiem":"Cứ điểm phòng ngự tuyến trước dựa hoàn toàn vào đại trận, một khi đại trận bị phá thì mất khả năng cố thủ.","congNang":["Đại trận phòng thủ dùng để trấn giữ cứ điểm, chống đỡ công kích từ bên ngoài (@c0728)"]},{"id":"bai-hoa-bo","name":"Bái Hỏa Bộ","cn":"拜火部","type":"bo-lac","typeLabel":"Bộ lạc","diaBan":"Thuộc phe Mộ Lan pháp sĩ","nhanVatChinh":["Quật Diệu"],"blurb":"Bộ lạc thuộc phe Mộ Lan pháp sĩ, có Đại Thượng Sư Quật Diệu sở hữu Thiên Địa Hỏa Linh có thể biến hóa thành hỏa giao.","detail":"Quật Diệu xưng danh Đại Thượng Sư Bái Hỏa Bộ khi khiêu chiến. Đây là lần đầu tiên tiết lộ tên bộ lạc cụ thể trong phe Mộ Lan pháp sĩ. Chuyên về hỏa thuộc tính.","nguonGoc":"Thuộc phe Mộ Lan pháp sĩ","thanhVien":[{"ten":"Quật Diệu","chucVu":"Đại Thượng Sư","tuChuong":"@c0729","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0729","loai":"xuất hiện","importance":"normal","giaiDoan":"Quật Diệu xưng danh","text":"Quật Diệu xưng danh Đại Thượng Sư Bái Hỏa Bộ, lần đầu tiết lộ tên bộ lạc cụ thể trong phe Mộ Lan.","anchor":"Tại hạ Bái Hỏa Bộ Đại Thượng Sư Quật Diệu"}]},"nguon":["@c0729"]},{"id":"bang-dai-de-quoc","name":"Bàng Đại đế quốc","cn":"","type":"de-quoc","typeLabel":"Đế quốc","diaBan":"Bên kia thảo nguyên Mộ Lan","nhanVatChinh":["Hắc bào nhân"],"blurb":"Đế quốc nằm bên kia thảo nguyên Mộ Lan, nơi hắc bào nhân Thiên Khốc đến từ đó. Thiên Khốc đã đạt thỏa thuận với Thần Sư tam đại bộ lạc Mộ Lan.","detail":"Bàng Đại đế quốc nằm bên kia thảo nguyên Mộ Lan. Hắc bào nhân Thiên Khốc (Nguyên Anh kỳ) được xác nhận đến từ đế quốc này. Thiên Khốc sở hữu công pháp thần thông vượt xa tu sĩ cùng cấp Thiên Nam, đã tiêu diệt hai tu sĩ Nguyên Anh Thiên Nam trước đó. Hai Đại Thượng Sư Mộ Lan biết rõ bảy tám phần lai lịch, xác nhận Thiên Khốc đã đạt thỏa thuận với Thần Sư tam đại bộ lạc.","tabs":{"tienTrinh":[{"chuong":"@c0732","loai":"nhắc tới","importance":"normal","giaiDoan":"Lộ lai lịch Thiên Khốc","text":"Hắc bào nhân Thiên Khốc được xác nhận đến từ Bàng Đại đế quốc bên kia thảo nguyên Mộ Lan, đã đạt thỏa thuận với Thần Sư tam đại bộ lạc.","anchor":"Tu sĩ thần bí này là đến từ Bàng Đại đế quốc bên kia thảo nguyên Mộ Lan"}]},"nguon":["@c0732"]},{"id":"nguoi-dot-ngot","name":"Người Đột Ngột","cn":"突骨人","type":"faction","typeLabel":"Thế lực thảo nguyên","diaBan":"Thảo nguyên (bao gồm hơn nửa thảo nguyên Mộ Lan đã chiếm)","nhanVatChinh":[],"blurb":"Thế lực hùng mạnh trên thảo nguyên, đã đánh bại chủ lực Mộ Lan trong quyết chiến và chiếm hơn nửa thảo nguyên Mộ Lan, xưng bá thảo nguyên.","detail":"Người Đột Ngột là thế lực đối địch chính của người Mộ Lan trên thảo nguyên. Trong một trận quyết chiến, chủ lực Mộ Lan đại bại trước người Đột Ngột, dẫn đến hơn nửa thảo nguyên Mộ Lan bị chiếm cứ. Chính thất bại này khiến người Mộ Lan rơi vào tình cảnh tuyệt vọng, buộc phải liều lĩnh xâm lược Thiên Nam để chiếm đoạt tư nguyên tu luyện, với hy vọng tăng cường thực lực rồi quay lại đánh bại người Đột Ngột. Người Đột Ngột có các tiên sư mà Mộ Lan muốn đánh tan nhưng chưa đủ lực.","nguon":["@c0733"]},{"id":"kim-duong-bo","name":"Kim Dương bộ","cn":"金阳部","type":"bo-lac","typeLabel":"Bộ lạc","diaBan":"Mộ Lan thảo nguyên","nhanVatChinh":[],"blurb":"Đệ nhất đại bộ lạc Mộ Lan, ở lại giám sát cử động của người Đột Ngột nên không tham chiến Thiên Nam.","detail":"Kim Dương bộ là đệ nhất đại bộ lạc của Mộ Lan tộc. Trong cuộc xâm lược Thiên Nam, bộ lạc này ở lại thảo nguyên giám sát cử động của người Đột Ngột thay vì kéo xuống tham chiến.","nguon":["@c0745"]},{"id":"hao-nhien-tong","name":"Hạo Nhiên tông","cn":"浩然宗","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Thiên Nam","nhanVatChinh":["Lão giả họ Mã"],"blurb":"Tông môn tại Thiên Nam, trưởng lão họ Mã phải bỏ nhục thân trốn về sau trận Hoàng Long Sơn.","detail":"Tông môn tu tiên tại Thiên Nam. Trưởng lão họ Mã (tu sĩ Nguyên Anh kỳ) tham chiến tại Hoàng Long Sơn, khi đối mặt phong độn thuật của nữ tử họ Nhạc chỉ có thể bỏ nhục thân, xuất khiếu Nguyên Anh trốn về Cửu Quốc Minh.","nguon":["@c0745"]},{"id":"loan-minh-mon","name":"Loan Minh Môn","cn":"鸾鸣门","aliases":["Loan Minh Tông"],"type":"tong-phai","typeLabel":"Tông phái","diaBan":"Thiên Nam","nhanVatChinh":["Trưởng lão mi dài Loan Minh Môn"],"blurb":"Tông phái mạnh nhất Thiên Đạo Minh. Đôi phu thê trưởng lão liên thủ có thể chống cự tam đại tu sĩ Thiên Nam.","detail":"Tông phái mạnh nhất trong liên minh Thiên Đạo Minh. Có đôi phu thê trưởng lão mà khi liên thủ có thể chống cự lại tam đại tu sĩ của Thiên Nam. Trưởng lão mi dài ngầm ghen tức trước sự trỗi dậy của Lạc Vân Tông nhờ Hàn Lập.","lanhDaoHienThoi":"Đôi phu thê trưởng lão","quyMo":"Mạnh nhất Thiên Đạo Minh","caoThuManhNhat":"Đôi phu thê trưởng lão (liên thủ chống cự tam đại tu sĩ Thiên Nam)","trangThai":"hoat-dong","capNhatToi":"@c0746","tabs":{"tienTrinh":[{"chuong":"@c0746","loai":"nhac-toi","importance":"normal","giaiDoan":"Được giới thiệu là tông phái mạnh nhất Thiên Đạo Minh","text":"Đôi phu thê trưởng lão liên thủ có thể chống cự tam đại tu sĩ Thiên Nam. Trưởng lão mi dài ngầm ghen tức trước sự trỗi dậy của Lạc Vân Tông nhờ Hàn Lập.","anchor":"đôi phu thê trưởng lão của môn phái này nếu liên thủ thì có thể chống cự lại tam đại tu sĩ của Thiên Nam"}]},"nguon":["@c0746"]},{"id":"thuy-anh-tong","name":"Thủy Ảnh Tông","type":"tong-phai","typeLabel":"Tông phái","diaBan":"Thiên Nam","nhanVatChinh":["Từ Trường Cảnh"],"blurb":"Tông phái thuộc liên minh Thiên Đạo Minh. Từ Trường Cảnh là trưởng lão, tu vi Nguyên Anh sơ kỳ.","detail":"Tông phái thuộc liên minh Thiên Đạo Minh, có Từ Trường Cảnh là trưởng lão tu vi Nguyên Anh sơ kỳ.","trangThai":"hoat-dong","capNhatToi":"@c0746","nguon":["@c0746"]},{"id":"nghe-hang-trai","name":"Nghê Hàng Trai","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Thiên Nam","nhanVatChinh":["Tu sĩ họ Huống"],"blurb":"Một trong ba phái khởi xướng Thiên Đạo Minh. Tu sĩ họ Huống với Kiền Thổ Công uy chấn Thiên Nam là đại diện nổi bật.","detail":"Một trong ba đại phái khởi xướng liên minh Thiên Đạo Minh (cùng Loan Minh Tông và Cổ Kiếm Môn). Vị trí trong trưởng lão hội không thay đổi. Tu sĩ họ Huống (Nguyên Anh trung kỳ) là đại diện tại đại điện nghị sự, nổi danh với Kiền Thổ Công.","thanhVien":[{"ten":"Tu sĩ họ Huống","chucVu":"Trưởng lão","tuChuong":"@c0747","trangThai":"tai-vị"}],"tabs":{"tienTrinh":[{"chuong":"@c0747","loai":"nhắc tới","importance":"normal","giaiDoan":"Được giới thiệu","text":"Được Lữ Lạc giới thiệu là một trong ba phái khởi xướng Thiên Đạo Minh.","anchor":"Huống huynh của Nghê Hàng Trai"}]},"nguon":["@c0747"]},{"id":"thien-phu-mon","name":"Thiên Phù môn","type":"tong-phai","typeLabel":"Tông phái","diaBan":"Đại Tấn quốc","nhanVatChinh":[],"blurb":"Tông phái mà Hàn Lập cần ghé giao trả hộp xương chứa phương pháp luyện Hàng Linh phù nếu có dịp đi Đại Tấn quốc.","detail":"Hàn Lập nhớ tới lời hứa phải ghé Thiên Phù môn giao trả hộp xương nhận từ Âm Minh chi địa nếu đi Đại Tấn quốc.","nguon":["@c0748"]},{"id":"tong-gia","name":"Tống gia","cn":"宋家","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Thiên Nam","nhanVatChinh":["Nữ tử họ Tống"],"blurb":"Gia tộc tu tiên của nữ tử họ Tống, sở hữu bản cổ tịch bí truyền về linh đan linh dược thượng cổ nhưng không đủ năng lực thu thập nguyên liệu.","detail":"Gia tộc tu tiên có truyền thừa bản cổ thư chuyên về linh đan và linh dược thời thượng cổ. Tuy sở hữu nhiều phương thuốc quý nhưng nguyên liệu đều khả ngộ bất khả cầu, gia tộc không đủ thực lực thu thập.","nguon":["@c0750"]},{"id":"thai-chan-mon","name":"Thái Chân môn","cn":"太真门","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Thiên Nam","nhanVatChinh":["Chí Dương thượng nhân"],"blurb":"Tông môn thuộc Chính Đạo minh ở Thiên Nam. Chí Dương thượng nhân là đại diện, một trong ba vị chủ trì hội nghị Thiên Nam đối phó Mộ Lan nhân.","detail":"Thái Chân môn thuộc Chính Đạo minh, sở hữu Tĩnh Tâm quyết. Chí Dương thượng nhân đại diện tông môn chủ trì hội nghị Thiên Nam, phân tích chiến cục và khẳng định buộc phải tham gia đổ chiến sinh tử.","lanhDaoHienThoi":"Chí Dương thượng nhân (đại diện)","thanhVien":[{"ten":"Chí Dương thượng nhân","chucVu":"Đại diện chủ trì hội nghị","tuChuong":"@c0755","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0755","loai":"xuất hiện","importance":"normal","giaiDoan":"Hội nghị Thiên Nam","trangThaiMoc":"hoat-dong","text":"Chí Dương thượng nhân đại diện Thái Chân môn chủ trì hội nghị Thiên Nam.","anchor":"Chí Dương thượng nhân của Thái Chân môn thuộc Chính Đạo minh"}]},"capNhatToi":"@c0755","nguon":["@c0755"]},{"id":"am-la-tong","name":"Âm La Tông","cn":"阴罗宗","type":"ma-tong","typeLabel":"Ma Tông","diaBan":"Đại Tấn quốc","nhanVatChinh":["Phòng tông chủ","Nữ tử áo đen (Âm La Tông)"],"blurb":"Âm La Tông là một trong mười đại Ma Tông của Đại Tấn, sở hữu bí thuật đồng giáp thi binh và cự thú. Trấn tông chi bảo Quỷ La Phiên bị chính đạo phá hủy, tông phái liên minh với Mộ Lan tộc tham gia đại chiến Thiên Nam để đổi lấy sinh hồn chiến trường phục hồi bảo vật.","detail":"Âm La Tông là ma tông lâu đời tại Đại Tấn, xếp vào hàng mười đại Ma Tông. Trấn tông chi bảo Quỷ La Phiên bị chính đạo phá hủy, cần lượng lớn sinh hồn để chữa trị, đây là động cơ chính khiến tông phái tham chiến tại Thiên Nam. Tông chủ Phòng mỗ đại diện Âm La Tông liên minh cùng Mộ Lan tộc, đổi cự thú và đồng giáp thi binh lấy quyền quản lý phàm nhân Yến tộc, thu hoạch sinh hồn chiến trường, cùng bắt sống tu sĩ Thiên Nam để sử dụng Ích Tà Thần Lôi. Âm La Tông tự coi thượng cổ ma công mới là chính thống, khinh thường ma tu Thiên Nam cho là thô thiển. Trong đại chiến, tông phái đã mất một trưởng lão bị tu sĩ Thiên Nam cùng cấp Hàn Lập diệt sát trong nháy mắt.","nguonGoc":"Ma Tông lâu đời tại Đại Tấn","lanhDaoHienThoi":"Phòng tông chủ","capBac":"Mười đại Ma Tông Đại Tấn","quanHe":[{"ten":"Mộ Lan tộc","loai":"lien-minh","ghiChu":"Liên minh tạm thời đại chiến Thiên Nam"}],"trangThai":"Trấn tông bảo bị hủy, đang suy, tham chiến Thiên Nam","thanhVien":[{"ten":"Phòng tông chủ","chucVu":"Tông chủ","tuChuong":"@c0762","trangThai":"hoat-dong"},{"ten":"Nữ tử áo đen (Âm La Tông)","chucVu":"Tùy tùng","tuChuong":"@c0762","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0762","loai":"lien-minh","importance":"major","trangThaiMoc":"Liên minh Mộ Lan tộc","text":"Tông chủ Phòng mỗ đại diện Âm La Tông liên minh với Mộ Lan tộc tham gia đại chiến Thiên Nam. Đổi cự thú và đồng giáp thi binh lấy quyền quản lý phàm nhân Yến tộc, sinh hồn chiến trường, và bắt sống tu sĩ dùng Ích Tà Thần Lôi.","anchor":"Tốt xấu gì Âm La Tông các ngươi cũng là một trong mười đại Ma Tông của Đại Tấn"}]},"nguon":["@c0762","@c0781"],"dacDiem":"Tự coi thượng cổ ma công là chính thống, khinh thường ma tu Thiên Nam. Sở hữu bí thuật đồng giáp thi binh và cự thú, trấn tông chi bảo là Quỷ La Phiên."},{"id":"quy-linh-tong","name":"Quỷ Linh Tông","type":"tong-mon","typeLabel":"Tông môn","blurb":"Một trong Ma Đạo Lục Tông, sở hữu vạn hồn đại trận, công pháp tương tự nhóm Hắc bào nhân bí ẩn.","detail":"Tông phái thuộc Ma Đạo Lục Tông. Chuẩn bị vạn hồn đại trận cho đại chiến Thiên Nam. Công pháp của Quỷ Linh Tông giống với nhóm Hắc bào nhân bí ẩn (bị nghi từ Đại Tấn quốc Ma Tông), nhưng Hắc bào nhân tinh thuần hơn.","nhanVatChinh":[],"tabs":{"tienTrinh":[{"chuong":"@c0763","loai":"xuat-hien","importance":"normal","giaiDoan":"Chuẩn bị vạn hồn đại trận","text":"Quỷ Linh Tông chuẩn bị vạn hồn đại trận sẵn sàng sử dụng trong đại chiến.","anchor":"Quỷ Linh Tông với vạn hồn đại trận tùy lúc cũng có thể bắt đầu dùng"}]},"nguon":["@c0763"]},{"id":"tong-phai-phong-tong-chu","name":"Tông phái Phòng tông chủ","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Không rõ (phe Mộ Lan)","nhanVatChinh":["Phòng tông chủ"],"blurb":"Tông phái ma đạo bí ẩn do Phòng tông chủ đứng đầu, sở hữu sáu đại bí thuật. Tại chiến trường biên giới, tông phái này đã thi triển Huyết La Quang Tráo hy sinh mười huyết thi trăm năm để vây khốn cả mười Nguyên Anh tu sĩ Thiên Nam.","detail":"Tông phái của Phòng tông chủ là một thế lực ma đạo, nguồn gốc không rõ ràng. Tông phái này có khả năng bồi dưỡng huyết thi trăm năm và nắm giữ sáu đại bí thuật, trong đó nổi bật nhất là Huyết La Quang Tráo. Trong cuộc chiến biên giới chống lại tu sĩ Thiên Nam, tông phái đã phối hợp cùng pháp sĩ Mộ Lan, hy sinh mười huyết thi trăm năm để thi triển Huyết La Quang Tráo, vây khốn toàn bộ mười vị Nguyên Anh tu sĩ phía Thiên Nam.","nguonGoc":"Không rõ","lanhDaoHienThoi":"Phòng tông chủ","trangThai":"Đang hoạt động, hợp tác phe Mộ Lan","capNhatToi":"@c0766","thanhVien":[{"ten":"Phòng tông chủ","chucVu":"Tông chủ","tuChuong":"@c0766","trangThai":"Đang hoạt động"}],"tabs":{"tienTrinh":[{"chuong":"@c0766","loai":"khai chiến","importance":"major","giaiDoan":"Thi triển Huyết La Quang Tráo tại chiến trường biên giới","trangThaiMoc":"Đang hợp tác phe Mộ Lan, mưu kế thành công","text":"Hy sinh mười huyết thi trăm năm thi triển Huyết La Quang Tráo vây khốn cả mười Nguyên Anh tu sĩ Thiên Nam tại chiến trường biên giới.","anchor":"Huyết la quang tráo là một trong sáu đại bí thuật của tông phái"}]},"nguon":["@c0766"],"uyLuc":"Hy sinh mười huyết thi trăm năm thi triển Huyết La Quang Tráo, vây khốn được cả mười Nguyên Anh tu sĩ Thiên Nam tại chiến trường biên giới.","congNang":["Bồi dưỡng huyết thi trăm năm, sử dụng làm vật liệu thi triển bí thuật","Thi triển Huyết La Quang Tráo — hy sinh mười huyết thi trăm năm để vây khốn cả mười Nguyên Anh tu sĩ cùng lúc @c0766"]},{"id":"tan-quoc-ma-tong","name":"Tấn quốc Ma Tông","cn":"","type":"ma-tong","typeLabel":"Ma Tông","diaBan":"Tấn quốc","nhanVatChinh":[],"blurb":"Thế lực ma đạo ở Tấn quốc, tương trợ pháp sĩ Mộ Lan bằng cách cung cấp hàng ngàn đồng giáp thi cho chiến trường Thiên Nam.","detail":"Được Long Hàm nhận định là nguồn cung cấp đồng giáp thi cho phe Mộ Lan trên chiến trường Thiên Nam. Việc Tấn quốc Ma Tông can dự cho thấy cuộc chiến không chỉ giới hạn Thiên Nam mà còn có sự nhúng tay của thế lực bên ngoài.","tabs":{"tienTrinh":[{"chuong":"@c0775","loai":"liên minh","importance":"normal","giaiDoan":"Tương trợ Mộ Lan bằng đồng giáp thi","trangThaiMoc":"liên minh với Mộ Lan","text":"Được Long Hàm nhắc tên là nguồn tương trợ đồng giáp thi cho pháp sĩ Mộ Lan trên chiến trường Thiên Nam.","anchor":"Người Mộ Lan đã có Tấn quốc Ma Tông tương trợ"}]},"nguon":["@c0775"]}]};
